 1‚Üí// Rundeus Relay ‚Äî Cloudflare Worker entry point.
 2‚Üí// Routes WebSocket upgrades to the RelayDO (one Durable Object per Deus server).
 3‚Üí
 4‚Üíimport { Hono } from "hono";
 5‚Üíimport { cors } from "hono/cors";
 6‚Üíimport { createMiddleware } from "hono/factory";
 7‚Üíimport type { Bindings } from "./types";
 8‚Üí
 9‚Üíexport { RelayDO } from "./relay-do";
10‚Üí
11‚Üíconst app = new Hono<{ Bindings: Bindings }>();
12‚Üí
13‚Üí// CORS for web portal and local dev
14‚Üíapp.use(
15‚Üí	"*",
16‚Üí	cors({
17‚Üí		origin: ["https://app.rundeus.com", "http://localhost:3000", "http://localhost:5173"],
18‚Üí		allowMethods: ["GET", "POST", "OPTIONS"],
19‚Üí		allowHeaders: ["Content-Type", "Authorization"],
20‚Üí	}),
21‚Üí);
22‚Üí
23‚Üí// Middleware: validate serverId and attach DO stub to context
24‚Üíconst withRelay = createMiddleware<{
25‚Üí	Bindings: Bindings;
26‚Üí	Variables: { stub: DurableObjectStub };
27‚Üí}>(async (c, next) => {
28‚Üí	const serverId = c.req.param("serverId");
29‚Üí	if (!serverId || !/^[a-z0-9]{4,8}$/i.test(serverId)) {
30‚Üí		return c.json({ error: "Invalid server ID" }, { status: 400 });
31‚Üí	}
32‚Üí	const id = c.env.RELAY.idFromName(serverId);
33‚Üí	c.set("stub", c.env.RELAY.get(id));
34‚Üí	await next();
35‚Üí});
36‚Üí
37‚Üí// Health check
38‚Üíapp.get("/health", (c) =>
39‚Üí	c.json({
40‚Üí		status: "ok",
41‚Üí		timestamp: new Date().toISOString(),
42‚Üí		service: "rundeus-relay",
43‚Üí	}),
44‚Üí);
45‚Üí
46‚Üí// Server tunnel ‚Äî Deus server connects here to register with the relay
47‚Üíapp.get("/api/servers/:serverId/tunnel", withRelay, async (c) => {
48‚Üí	const stub = c.get("stub");
49‚Üí	const tunnelUrl = new URL(c.req.url);
50‚Üí	tunnelUrl.pathname = "/tunnel";
51‚Üí	return stub.fetch(new Request(tunnelUrl, c.req.raw));
52‚Üí});
53‚Üí
54‚Üí// Client connect ‚Äî remote web/mobile clients connect here
55‚Üíapp.get("/api/servers/:serverId/connect", withRelay, async (c) => {
56‚Üí	const stub = c.get("stub");
57‚Üí	const connectUrl = new URL(c.req.url);
58‚Üí	connectUrl.pathname = "/connect";
59‚Üí	return stub.fetch(new Request(connectUrl, c.req.raw));
60‚Üí});
61‚Üí
62‚Üí// Pairing exchange ‚Äî web portal exchanges a code for a device token
63‚Üíapp.get("/api/servers/:serverId/pair", withRelay, async (c) => {
64‚Üí	const stub = c.get("stub");
65‚Üí	const pairUrl = new URL(c.req.url);
66‚Üí	pairUrl.pathname = "/pair";
67‚Üí	return stub.fetch(new Request(pairUrl, c.req.raw));
68‚Üí});
69‚Üí
70‚Üí// Server status ‚Äî check if a server is online
71‚Üíapp.get("/api/servers/:serverId/status", withRelay, async (c) => {
72‚Üí	const stub = c.get("stub");
73‚Üí	return stub.fetch(new Request(new URL("/status", c.req.url)));
74‚Üí});
75‚Üí
76‚Üí// Root
77‚Üíapp.get("/", (c) =>
78‚Üí	c.json({
79‚Üí		name: "rundeus-relay",
80‚Üí		version: "0.1.0",
81‚Üí		docs: "https://app.rundeus.com",
82‚Üí	}),
83‚Üí);
84‚Üí
85‚Üíexport default app;
86‚Üí

  1‚Üíimport * as Sentry from "@sentry/node";
  2‚Üíimport { serve } from "@hono/node-server";
  3‚Üíimport { createApp } from "./app";
  4‚Üíimport { initDatabase, closeDatabase, DB_PATH } from "./lib/database";
  5‚Üíimport { closeAll as closeAllWsConnections } from "./services/ws.service";
  6‚Üíimport { ensureRelayConnected, disconnectFromRelay } from "./services/relay.service";
  7‚Üíimport { getSetting } from "./services/settings.service";
  8‚Üíimport * as agentService from "./services/agent";
  9‚Üíimport { stopBrowserServer } from "./services/browser-server.service";
 10‚Üíimport { destroyAllPtySessions } from "./services/pty.service";
 11‚Üíimport { destroyAllWatchers } from "./services/fs-watcher.service";
 12‚Üí
 13‚Üí// Initialize Sentry before anything else.
 14‚Üí// DSN passed as env var from Electron main process (not hardcoded ‚Äî open source repo).
 15‚Üíif (process.env.SENTRY_DSN) {
 16‚Üí  Sentry.init({
 17‚Üí    dsn: process.env.SENTRY_DSN,
 18‚Üí    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 19‚Üí    sendDefaultPii: false,
 20‚Üí    initialScope: { tags: { process: "backend" } },
 21‚Üí  });
 22‚Üí}
 23‚Üí
 24‚Üí/**
 25‚Üí * OpenDevs Backend Server
 26‚Üí *
 27‚Üí * Handles workspace CRUD, sessions, repos, config, and stats.
 28‚Üí * Agent runtime (Claude SDK) is managed by the agent-server (sidecar).
 29‚Üí */
 30‚Üí
 31‚Üí// Initialize database
 32‚Üíconst db = initDatabase();
 33‚Üí
 34‚Üí// Create Hono app + WebSocket injector
 35‚Üíconst { app, injectWebSocket } = createApp();
 36‚Üí
 37‚Üí// Global variable to store actual port (used by health endpoint)
 38‚Üílet actualServerPort: number | null = null;
 39‚Üí
 40‚Üíexport function getServerPort() {
 41‚Üí  return actualServerPort;
 42‚Üí}
 43‚Üí
 44‚Üí// Start server with dynamic port allocation
 45‚Üíconst PORT = process.env.PORT ? parseInt(process.env.PORT) : 0;
 46‚Üí
 47‚Üí// Bind 0.0.0.0 to accept connections from all interfaces.
 48‚Üí// Remote access is gated by remoteGateMiddleware (rejects non-localhost when disabled).
 49‚Üíconst server = serve(
 50‚Üí  {
 51‚Üí    fetch: app.fetch,
 52‚Üí    port: PORT,
 53‚Üí    hostname: "0.0.0.0",
 54‚Üí  },
 55‚Üí  (info) => {
 56‚Üí    actualServerPort = info.port;
 57‚Üí
 58‚Üí    // CRITICAL: Machine-readable port output for Electron main process and dev.sh
 59‚Üí    console.log(`[BACKEND_PORT]${info.port}`);
 60‚Üí
 61‚Üí    console.log("\nOpenDevs Backend Server");
 62‚Üí    console.log(`API Server: http://0.0.0.0:${info.port}`);
 63‚Üí    console.log(`Database: ${DB_PATH}`);
 64‚Üí    console.log("Server ready!\n");
 65‚Üí  }
 66‚Üí);
 67‚Üí
 68‚Üí// Inject WebSocket support into the HTTP server
 69‚ÜíinjectWebSocket(server);
 70‚Üí
 71‚Üíconst remoteEnabled = getSetting("remote_access_enabled");
 72‚Üíif (remoteEnabled === true) {
 73‚Üí  ensureRelayConnected();
 74‚Üí}
 75‚Üí
 76‚Üí// Connect to agent-server (sidecar).
 77‚Üí//
 78‚Üí// Two bootstrap paths:
 79‚Üí// 1. AGENT_SERVER_URL is set (dev.sh): sidecar already running, connect directly.
 80‚Üí// 2. SIDECAR_BUNDLE_PATH is set (Electron): spawn sidecar as child process,
 81‚Üí//    parse LISTEN_URL from its stdout, then connect.
 82‚Üíconst agentServerUrl = process.env.AGENT_SERVER_URL;
 83‚Üíconst sidecarBundlePath = process.env.SIDECAR_BUNDLE_PATH;
 84‚Üí
 85‚Üíif (agentServerUrl) {
 86‚Üí  // Path 1: Direct connection (dev.sh spawned the sidecar externally)
 87‚Üí  agentService.init(agentServerUrl);
 88‚Üí} else if (sidecarBundlePath) {
 89‚Üí  // Path 2: Spawn sidecar and connect (Electron desktop mode)
 90‚Üí  void spawnSidecarAndConnect(sidecarBundlePath);
 91‚Üí}
 92‚Üí
 93‚Üí// Track sidecar child process for cleanup on shutdown
 94‚Üílet sidecarChild: import("child_process").ChildProcess | null = null;
 95‚Üí
 96‚Üífunction killSidecar(): void {
 97‚Üí  if (sidecarChild && !sidecarChild.killed) {
 98‚Üí    sidecarChild.kill("SIGTERM");
 99‚Üí    sidecarChild = null;
100‚Üí  }
101‚Üí}
102‚Üí
103‚Üí/** Spawn the sidecar bundle as a child process and connect to its WebSocket. */
104‚Üíasync function spawnSidecarAndConnect(bundlePath: string): Promise<void> {
105‚Üí  const { spawn } = await import("child_process");
106‚Üí  const fs = await import("fs");
107‚Üí
108‚Üí  if (!fs.existsSync(bundlePath)) {
109‚Üí    console.error(`[server] Sidecar bundle not found: ${bundlePath}`);
110‚Üí    return;
111‚Üí  }
112‚Üí
113‚Üí  sidecarChild = spawn(process.execPath, [bundlePath], {
114‚Üí    stdio: ["ignore", "pipe", "pipe"],
115‚Üí    env: {
116‚Üí      ...process.env,
117‚Üí      // Forward database path so sidecar can pass it to agents
118‚Üí      DATABASE_PATH: process.env.DATABASE_PATH,
119‚Üí      // Forward notebook server path
120‚Üí      NOTEBOOK_SERVER_BUNDLE_PATH: process.env.NOTEBOOK_SERVER_BUNDLE_PATH,
121‚Üí    },
122‚Üí  });
123‚Üí
124‚Üí  const sidecar = sidecarChild!;
125‚Üí  let stdoutBuffer = "";
126‚Üí
127‚Üí  sidecar.stdout?.on("data", (data: Buffer) => {
128‚Üí    stdoutBuffer += data.toString();
129‚Üí    const lines = stdoutBuffer.split("\n");
130‚Üí    stdoutBuffer = lines.pop() ?? "";
131‚Üí
132‚Üí    for (const line of lines) {
133‚Üí      const trimmed = line.trim();
134‚Üí      if (!trimmed) continue;
135‚Üí      console.log("[sidecar]", trimmed);
136‚Üí
137‚Üí      // Capture the LISTEN_URL and connect
138‚Üí      if (trimmed.startsWith("LISTEN_URL=")) {
139‚Üí        const url = trimmed.slice("LISTEN_URL=".length);
140‚Üí        console.log(`[server] Sidecar spawned and listening at ${url}`);
141‚Üí        agentService.init(url);
142‚Üí      }
143‚Üí    }
144‚Üí  });
145‚Üí
146‚Üí  sidecar.stderr?.on("data", (data: Buffer) => {
147‚Üí    for (const line of data.toString().split("\n")) {
148‚Üí      if (line.trim()) console.error("[sidecar:stderr]", line.trim());
149‚Üí    }
150‚Üí  });
151‚Üí
152‚Üí  sidecar.on("exit", (code, signal) => {
153‚Üí    console.log(`[sidecar] Exited with code=${code} signal=${signal}`);
154‚Üí    sidecarChild = null;
155‚Üí  });
156‚Üí}
157‚Üí
158‚Üí// Global error handlers
159‚Üíprocess.on("uncaughtException", (error, origin) => {
160‚Üí  console.error("[FATAL] Uncaught Exception:", origin, error);
161‚Üí  Sentry.captureException(error);
162‚Üí  Sentry.close(2000).finally(() => {
163‚Üí    stopBrowserServer();
164‚Üí    destroyAllPtySessions();
165‚Üí    destroyAllWatchers();
166‚Üí    killSidecar();
167‚Üí    try {
168‚Üí      closeDatabase();
169‚Üí    } catch {}
170‚Üí    process.exit(1);
171‚Üí  });
172‚Üí});
173‚Üí
174‚Üíprocess.on("unhandledRejection", (reason) => {
175‚Üí  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
176‚Üí  // rejection reasons automatically. We only log here for local visibility.
177‚Üí  console.error("[FATAL] Unhandled Promise Rejection:", reason);
178‚Üí});
179‚Üí
180‚Üí// Graceful shutdown
181‚Üífunction shutdown() {
182‚Üí  console.log("\nShutting down...");
183‚Üí  agentService.shutdown();
184‚Üí  stopBrowserServer();
185‚Üí  destroyAllPtySessions();
186‚Üí  destroyAllWatchers();
187‚Üí  killSidecar();
188‚Üí  disconnectFromRelay();
189‚Üí  closeAllWsConnections();
190‚Üí  closeDatabase();
191‚Üí  process.exit(0);
192‚Üí}
193‚Üí
194‚Üíprocess.on("SIGINT", shutdown);
195‚Üíprocess.on("SIGTERM", shutdown);
196‚Üí

