  1‚Üí// Cloudflare Durable Object for relay WebSocket multiplexing.
  2‚Üí// One DO per Deus server. Holds the server tunnel + all client connections.
  3‚Üí// Uses the WebSocket Hibernation API for efficient connection handling.
  4‚Üí// All mutable state lives in ctx.storage to survive hibernation.
  5‚Üí//
  6‚Üí// Storage keys:
  7‚Üí//   relayToken                   ‚Äî server's relay token (set on first registration)
  8‚Üí//   tunnelRegistered             ‚Äî boolean, true after successful register handshake
  9‚Üí//   serverDisconnectedAt         ‚Äî timestamp when server disconnected (persists until reconnect)
 10‚Üí//   pending:<clientId>           ‚Äî auth deadline timestamp for pending clients
 11‚Üí//   auth_token:<clientId>        ‚Äî client's device token (stored for re-forwarding on reconnect)
 12‚Üí//   pending:pair:<pairId>       ‚Äî deadline timestamp for one-shot pairing requests
 13‚Üí
 14‚Üíimport { DurableObject } from "cloudflare:workers";
 15‚Üíimport type {
 16‚Üí	PairerFrame,
 17‚Üí	RelayClientFrame,
 18‚Üí	RelayFrame,
 19‚Üí	RelayPairerFrame,
 20‚Üí	ServerFrame,
 21‚Üí} from "@cancun/types";
 22‚Üíimport { clientAuthFrameSchema, pairerFrameSchema, serverFrameSchema } from "@cancun/types";
 23‚Üí
 24‚Üíconst AUTH_TIMEOUT_MS = 5_000;
 25‚Üíconst OFFLINE_WAIT_MS = 300_000; // 5 min ‚Äî max time a client waits for server to reconnect
 26‚Üíconst HEARTBEAT_INTERVAL_MS = 30_000;
 27‚Üíconst PAIR_TIMEOUT_MS = 30_000;
 28‚Üí
 29‚Üíexport class RelayDO extends DurableObject {
 30‚Üí	async fetch(request: Request): Promise<Response> {
 31‚Üí		const url = new URL(request.url);
 32‚Üí
 33‚Üí		if (url.pathname === "/tunnel") {
 34‚Üí			return this.handleTunnel(request);
 35‚Üí		}
 36‚Üí		if (url.pathname === "/connect") {
 37‚Üí			return this.handleClient(request);
 38‚Üí		}
 39‚Üí		if (url.pathname === "/pair") {
 40‚Üí			return this.handlePairer(request);
 41‚Üí		}
 42‚Üí		if (url.pathname === "/status") {
 43‚Üí			return this.handleStatus();
 44‚Üí		}
 45‚Üí
 46‚Üí		return new Response("Not found", { status: 404 });
 47‚Üí	}
 48‚Üí
 49‚Üí	// ---- Server Tunnel ----
 50‚Üí
 51‚Üí	private async handleTunnel(request: Request): Promise<Response> {
 52‚Üí		// Authenticate BEFORE closing existing tunnels to prevent unauthenticated
 53‚Üí		// connections from disrupting a legitimate server's tunnel (DoS).
 54‚Üí		const storedToken = await this.ctx.storage.get<string>("relayToken");
 55‚Üí		if (storedToken) {
 56‚Üí			const url = new URL(request.url);
 57‚Üí			const token =
 58‚Üí				request.headers.get("Authorization")?.replace("Bearer ", "") ||
 59‚Üí				url.searchParams.get("token");
 60‚Üí			if (token !== storedToken) {
 61‚Üí				return new Response("Unauthorized", { status: 401 });
 62‚Üí			}
 63‚Üí		}
 64‚Üí
 65‚Üí		// Close any existing tunnel before accepting a new one to prevent
 66‚Üí		// stale connections from receiving messages meant for the new tunnel.
 67‚Üí		const existingTunnels = this.ctx.getWebSockets("tunnel");
 68‚Üí		for (const tunnel of existingTunnels) {
 69‚Üí			try {
 70‚Üí				tunnel.close(1000, "New tunnel connection");
 71‚Üí			} catch (err) {
 72‚Üí				console.error("relay: failed to close existing tunnel", err);
 73‚Üí			}
 74‚Üí		}
 75‚Üí
 76‚Üí		// New tunnel is not yet registered ‚Äî must complete register handshake first
 77‚Üí		await this.ctx.storage.put("tunnelRegistered", false);
 78‚Üí
 79‚Üí		const pair = new WebSocketPair();
 80‚Üí		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
 81‚Üí
 82‚Üí		this.ctx.acceptWebSocket(server, ["tunnel"]);
 83‚Üí
 84‚Üí		return new Response(null, { status: 101, webSocket: client });
 85‚Üí	}
 86‚Üí
 87‚Üí	// ---- Client Connection ----
 88‚Üí
 89‚Üí	private async handleClient(_request: Request): Promise<Response> {
 90‚Üí		const tunnels = this.ctx.getWebSockets("tunnel");
 91‚Üí		if (tunnels.length === 0) {
 92‚Üí			// Accept connections if server was ever registered ‚Äî it may come back.
 93‚Üí			// Only reject for completely unknown servers (never registered).
 94‚Üí			const hasEverRegistered = await this.ctx.storage.get<string>("relayToken");
 95‚Üí			if (!hasEverRegistered) {
 96‚Üí				return Response.json({ error: "server_not_found" }, { status: 503 });
 97‚Üí			}
 98‚Üí		}
 99‚Üí
100‚Üí		const pair = new WebSocketPair();
101‚Üí		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
102‚Üí
103‚Üí		const clientId = crypto.randomUUID();
104‚Üí		// Tags are immutable after acceptWebSocket ‚Äî don't encode mutable state in them.
105‚Üí		// Auth state is tracked via storage keys instead.
106‚Üí		this.ctx.acceptWebSocket(server, ["client", clientId]);
107‚Üí
108‚Üí		// Store auth deadline in durable storage (survives hibernation)
109‚Üí		await this.ctx.storage.put(`pending:${clientId}`, Date.now() + AUTH_TIMEOUT_MS);
110‚Üí		await this.scheduleNextAlarm();
111‚Üí
112‚Üí		return new Response(null, { status: 101, webSocket: client });
113‚Üí	}
114‚Üí
115‚Üí	// ---- Status ----
116‚Üí
117‚Üí	private async handleStatus(): Promise<Response> {
118‚Üí		const tunnels = this.ctx.getWebSockets("tunnel");
119‚Üí		const allClients = this.ctx.getWebSockets("client");
120‚Üí		const pendingClientCount = (await this.getPendingClients()).size;
121‚Üí		const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
122‚Üí		const serverName = await this.ctx.storage.get<string>("serverName");
123‚Üí
124‚Üí		return Response.json({
125‚Üí			online: tunnels.length > 0,
126‚Üí			clients: Math.max(0, allClients.length - pendingClientCount),
127‚Üí			reconnecting: serverDisconnectedAt !== undefined,
128‚Üí			serverDisconnectedAt: serverDisconnectedAt ?? null,
129‚Üí			serverName: serverName || null,
130‚Üí		});
131‚Üí	}
132‚Üí
133‚Üí	// ---- Pairing (one-shot code exchange) ----
134‚Üí
135‚Üí	private async handlePairer(_request: Request): Promise<Response> {
136‚Üí		// Pairing requires an active, registered server tunnel
137‚Üí		const tunnel = this.getTunnel();
138‚Üí		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
139‚Üí		if (!tunnel || !isRegistered) {
140‚Üí			return Response.json({ error: "server_offline" }, { status: 503 });
141‚Üí		}
142‚Üí
143‚Üí		const pair = new WebSocketPair();
144‚Üí		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
145‚Üí
146‚Üí		const pairId = crypto.randomUUID();
147‚Üí		this.ctx.acceptWebSocket(server, ["pairer", pairId]);
148‚Üí
149‚Üí		// Store deadline for cleanup via alarm
150‚Üí		await this.ctx.storage.put(`pending:pair:${pairId}`, Date.now() + PAIR_TIMEOUT_MS);
151‚Üí		await this.scheduleNextAlarm();
152‚Üí
153‚Üí		return new Response(null, { status: 101, webSocket: client });
154‚Üí	}
155‚Üí
156‚Üí	// ---- WebSocket Handlers (Hibernation API) ----
157‚Üí
158‚Üí	async webSocketMessage(ws: WebSocket, message: string | ArrayBuffer): Promise<void> {
159‚Üí		const tags = this.ctx.getTags(ws);
160‚Üí		const raw = typeof message === "string" ? message : new TextDecoder().decode(message);
161‚Üí
162‚Üí		let json: unknown;
163‚Üí		try {
164‚Üí			json = JSON.parse(raw);
165‚Üí		} catch {
166‚Üí			console.error("relay: failed to parse WebSocket message as JSON");
167‚Üí			return;
168‚Üí		}
169‚Üí
170‚Üí		if (tags.includes("tunnel")) {
171‚Üí			const result = serverFrameSchema.safeParse(json);
172‚Üí			if (!result.success) {
173‚Üí				console.error("relay: invalid server frame", result.error.issues);
174‚Üí				return;
175‚Üí			}
176‚Üí			await this.handleServerMessage(ws, result.data);
177‚Üí		} else if (tags.includes("pairer")) {
178‚Üí			const pairId = tags.find((t) => t !== "pairer");
179‚Üí			if (!pairId) return;
180‚Üí			const result = pairerFrameSchema.safeParse(json);
181‚Üí			if (!result.success) {
182‚Üí				console.error("relay: invalid pairer frame", result.error.issues);
183‚Üí				return;
184‚Üí			}
185‚Üí			await this.handlePairerMessage(pairId, result.data);
186‚Üí		} else if (tags.includes("client")) {
187‚Üí			const clientId = tags.find((t) => t !== "client");
188‚Üí			if (!clientId) return;
189‚Üí			await this.handleClientMessage(clientId, json);
190‚Üí		}
191‚Üí	}
192‚Üí
193‚Üí	async webSocketClose(
194‚Üí		ws: WebSocket,
195‚Üí		_code: number,
196‚Üí		_reason: string,
197‚Üí		_wasClean: boolean,
198‚Üí	): Promise<void> {
199‚Üí		const tags = this.ctx.getTags(ws);
200‚Üí
201‚Üí		if (tags.includes("tunnel")) {
202‚Üí			await this.handleServerDisconnect();
203‚Üí		} else if (tags.includes("pairer")) {
204‚Üí			const pairId = tags.find((t) => t !== "pairer");
205‚Üí			if (pairId) {
206‚Üí				await this.ctx.storage.delete(`pending:pair:${pairId}`);
207‚Üí			}
208‚Üí		} else if (tags.includes("client")) {
209‚Üí			const clientId = tags.find((t) => t !== "client");
210‚Üí			if (clientId) {
211‚Üí				await this.handleClientDisconnect(clientId);
212‚Üí			}
213‚Üí		}
214‚Üí	}
215‚Üí
216‚Üí	async webSocketError(ws: WebSocket, _error: unknown): Promise<void> {
217‚Üí		const tags = this.ctx.getTags(ws);
218‚Üí
219‚Üí		if (tags.includes("tunnel")) {
220‚Üí			await this.handleServerDisconnect();
221‚Üí		} else if (tags.includes("pairer")) {
222‚Üí			const pairId = tags.find((t) => t !== "pairer");
223‚Üí			if (pairId) {
224‚Üí				await this.ctx.storage.delete(`pending:pair:${pairId}`);
225‚Üí			}
226‚Üí		} else if (tags.includes("client")) {
227‚Üí			const clientId = tags.find((t) => t !== "client");
228‚Üí			if (clientId) {
229‚Üí				await this.handleClientDisconnect(clientId);
230‚Üí			}
231‚Üí		}
232‚Üí	}
233‚Üí
234‚Üí	// ---- Alarm (auth timeout + heartbeat) ----
235‚Üí
236‚Üí	async alarm(): Promise<void> {
237‚Üí		const now = Date.now();
238‚Üí
239‚Üí		// 1. Reject clients whose auth deadline has expired
240‚Üí		const pendingClients = await this.getPendingClients();
241‚Üí		const expiredClientIds: string[] = [];
242‚Üí		for (const [clientId, deadline] of pendingClients) {
243‚Üí			if (now >= deadline) {
244‚Üí				expiredClientIds.push(clientId);
245‚Üí			}
246‚Üí		}
247‚Üí		if (expiredClientIds.length > 0) {
248‚Üí			const keysToDelete = expiredClientIds.flatMap((id) => [`pending:${id}`, `auth_token:${id}`]);
249‚Üí			await this.ctx.storage.delete(keysToDelete);
250‚Üí			for (const clientId of expiredClientIds) {
251‚Üí				this.rejectClient(clientId, "Authentication timeout");
252‚Üí			}
253‚Üí		}
254‚Üí
255‚Üí		// 1b. Reject pairers whose deadline has expired
256‚Üí		const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
257‚Üí		for (const [key, deadline] of pendingPairs) {
258‚Üí			if (now >= deadline) {
259‚Üí				const pairId = key.slice("pending:pair:".length);
260‚Üí				const pairerWs = this.findPairerWs(pairId);
261‚Üí				if (pairerWs) {
262‚Üí					this.safeSend(pairerWs, { type: "pair_failed", message: "Pairing timed out" });
263‚Üí					try {
264‚Üí						pairerWs.close(1000, "Pairing timed out");
265‚Üí					} catch (err) {
266‚Üí						console.error("relay: failed to close expired pairer", err);
267‚Üí					}
268‚Üí				}
269‚Üí				await this.ctx.storage.delete(key);
270‚Üí			}
271‚Üí		}
272‚Üí
273‚Üí		// 2. Send heartbeat ping to server
274‚Üí		const tunnel = this.getTunnel();
275‚Üí		if (tunnel) {
276‚Üí			this.safeSend(tunnel, { type: "ping" });
277‚Üí		}
278‚Üí
279‚Üí		// 3. Reschedule for next event
280‚Üí		await this.scheduleNextAlarm();
281‚Üí	}
282‚Üí
283‚Üí	// ---- Server Message Handling ----
284‚Üí
285‚Üí	private async handleServerMessage(ws: WebSocket, frame: ServerFrame): Promise<void> {
286‚Üí		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
287‚Üí
288‚Üí		switch (frame.type) {
289‚Üí			case "register": {
290‚Üí				await this.handleRegister(ws, frame);
291‚Üí				break;
292‚Üí			}
293‚Üí			case "auth_response": {
294‚Üí				// Only registered tunnels may send auth_response
295‚Üí				if (!isRegistered) break;
296‚Üí				await this.handleAuthResponse(frame.clientId, frame.allowed, frame.reason);
297‚Üí				break;
298‚Üí			}
299‚Üí			case "pair_response": {
300‚Üí				if (!isRegistered) break;
301‚Üí				await this.ctx.storage.delete(`pending:pair:${frame.pairId}`);
302‚Üí				const pairerWs = this.findPairerWs(frame.pairId);
303‚Üí				if (!pairerWs) break;
304‚Üí				if (frame.success && frame.deviceToken) {
305‚Üí					this.safeSend(pairerWs, { type: "pair_success", token: frame.deviceToken });
306‚Üí				} else {
307‚Üí					this.safeSend(pairerWs, {
308‚Üí						type: "pair_failed",
309‚Üí						message: frame.reason || "Pairing failed",
310‚Üí					});
311‚Üí				}
312‚Üí				// Close the one-shot pairer WS ‚Äî buffered messages are sent before the close frame
313‚Üí				try {
314‚Üí					pairerWs.close(1000, "Pairing complete");
315‚Üí				} catch (err) {
316‚Üí					console.error("relay: failed to close pairer after response", err);
317‚Üí				}
318‚Üí				break;
319‚Üí			}
320‚Üí			case "data": {
321‚Üí				// Only registered tunnels may send data
322‚Üí				if (!isRegistered) break;
323‚Üí				await this.forwardToClient(frame.clientId, frame.payload);
324‚Üí				break;
325‚Üí			}
326‚Üí			case "pong": {
327‚Üí				break;
328‚Üí			}
329‚Üí		}
330‚Üí	}
331‚Üí
332‚Üí	private async handleRegister(
333‚Üí		ws: WebSocket,
334‚Üí		frame: Extract<ServerFrame, { type: "register" }>,
335‚Üí	): Promise<void> {
336‚Üí		const storedToken = await this.ctx.storage.get<string>("relayToken");
337‚Üí		if (storedToken && storedToken !== frame.relayToken) {
338‚Üí			this.safeSend(ws, { type: "error", message: "Invalid relay token" });
339‚Üí			try {
340‚Üí				ws.close(4003, "Invalid relay token");
341‚Üí			} catch (err) {
342‚Üí				console.error("relay: failed to close tunnel with bad token", err);
343‚Üí			}
344‚Üí			return;
345‚Üí		}
346‚Üí
347‚Üí		if (!storedToken) {
348‚Üí			await this.ctx.storage.put("relayToken", frame.relayToken);
349‚Üí		}
350‚Üí
351‚Üí		// Always update server name (user might have changed it)
352‚Üí		if (frame.serverName) {
353‚Üí			await this.ctx.storage.put("serverName", frame.serverName);
354‚Üí		}
355‚Üí
356‚Üí		// Mark tunnel as registered ‚Äî gates auth_response/data processing
357‚Üí		await this.ctx.storage.put("tunnelRegistered", true);
358‚Üí
359‚Üí		// Clear reconnection state and notify clients server is back
360‚Üí		const wasReconnecting = await this.ctx.storage.get<number>("serverDisconnectedAt");
361‚Üí		await this.ctx.storage.delete("serverDisconnectedAt");
362‚Üí
363‚Üí		// Confirm registration to the WebSocket that sent it
364‚Üí		this.safeSend(ws, { type: "registered" });
365‚Üí
366‚Üí		// Notify already-authenticated clients that the server is back.
367‚Üí		// Pending clients are notified via the normal auth flow (they'll get "authenticated").
368‚Üí		if (wasReconnecting !== undefined) {
369‚Üí			const clients = this.ctx.getWebSockets("client");
370‚Üí			for (const clientWs of clients) {
371‚Üí				const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
372‚Üí				if (!clientId) continue;
373‚Üí				const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
374‚Üí				if (isPending !== undefined) continue;
375‚Üí				this.safeSend(clientWs, { type: "server_connected" });
376‚Üí			}
377‚Üí		}
378‚Üí
379‚Üí		// Always re-forward pending clients' stored auth tokens to the new tunnel.
380‚Üí		// This handles both reconnection (wasReconnecting) and tunnel replacement
381‚Üí		// (where serverDisconnectedAt was never set because the old tunnel's close
382‚Üí		// handler saw the new tunnel already existed).
383‚Üí		const pendingClients = await this.getPendingClients();
384‚Üí		for (const [pendingClientId] of pendingClients) {
385‚Üí			const storedAuthToken = await this.ctx.storage.get<string>(`auth_token:${pendingClientId}`);
386‚Üí			if (storedAuthToken) {
387‚Üí				this.safeSend(ws, {
388‚Üí					type: "client_connected",
389‚Üí					clientId: pendingClientId,
390‚Üí					deviceToken: storedAuthToken,
391‚Üí				});
392‚Üí			}
393‚Üí		}
394‚Üí
395‚Üí		// Start heartbeat
396‚Üí		await this.scheduleNextAlarm();
397‚Üí	}
398‚Üí
399‚Üí	// ---- Auth Delegation ----
400‚Üí
401‚Üí	private async handleAuthResponse(
402‚Üí		clientId: string,
403‚Üí		allowed: boolean,
404‚Üí		reason?: string,
405‚Üí	): Promise<void> {
406‚Üí		await this.ctx.storage.delete(`pending:${clientId}`);
407‚Üí		await this.ctx.storage.delete(`auth_token:${clientId}`);
408‚Üí
409‚Üí		if (allowed) {
410‚Üí			this.activateClient(clientId);
411‚Üí		} else {
412‚Üí			this.rejectClient(clientId, reason || "Authentication denied");
413‚Üí		}
414‚Üí	}
415‚Üí
416‚Üí	private activateClient(clientId: string): void {
417‚Üí		const ws = this.findClientWs(clientId);
418‚Üí		if (ws) {
419‚Üí			this.safeSend(ws, { type: "authenticated" });
420‚Üí		}
421‚Üí	}
422‚Üí
423‚Üí	private rejectClient(clientId: string, message: string): void {
424‚Üí		const ws = this.findClientWs(clientId);
425‚Üí		if (ws) {
426‚Üí			this.safeSend(ws, { type: "auth_failed", message });
427‚Üí			try {
428‚Üí				ws.close(4003, message);
429‚Üí			} catch (err) {
430‚Üí				console.error(`relay: failed to close rejected client ${clientId}`, err);
431‚Üí			}
432‚Üí		}
433‚Üí	}
434‚Üí
435‚Üí	// ---- Client Message Handling ----
436‚Üí
437‚Üí	private async handleClientMessage(clientId: string, json: unknown): Promise<void> {
438‚Üí		const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
439‚Üí
440‚Üí		if (isPending !== undefined) {
441‚Üí			// Client is still pending ‚Äî only accept authenticate messages
442‚Üí			const authResult = clientAuthFrameSchema.safeParse(json);
443‚Üí			if (!authResult.success) return;
444‚Üí
445‚Üí			const { token } = authResult.data;
446‚Üí			// Store the token so we can re-forward it if the server reconnects
447‚Üí			await this.ctx.storage.put(`auth_token:${clientId}`, token);
448‚Üí
449‚Üí			const tunnel = this.getTunnel();
450‚Üí			const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
451‚Üí			if (tunnel && isRegistered) {
452‚Üí				this.safeSend(tunnel, {
453‚Üí					type: "client_connected",
454‚Üí					clientId,
455‚Üí					deviceToken: token,
456‚Üí				});
457‚Üí			} else if (tunnel) {
458‚Üí				// Tunnel exists but not yet registered ‚Äî replacement in progress.
459‚Üí				// Leave client pending; handleRegister will re-forward the stored
460‚Üí				// auth token once the new tunnel completes registration.
461‚Üí				// The auth timeout alarm will reject naturally if registration never comes.
462‚Üí			} else {
463‚Üí				// Server tunnel is down ‚Äî keep client waiting for server to return.
464‚Üí				// Suspend the short auth deadline; handleRegister will re-forward the
465‚Üí				// stored auth token when the server reconnects.
466‚Üí				const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
467‚Üí				await this.ctx.storage.put(`pending:${clientId}`, Date.now() + OFFLINE_WAIT_MS);
468‚Üí				const clientWs = this.findClientWs(clientId);
469‚Üí				if (clientWs) {
470‚Üí					const serverName = await this.ctx.storage.get<string>("serverName");
471‚Üí					this.safeSend(clientWs, {
472‚Üí						type: "server_reconnecting",
473‚Üí						serverDisconnectedAt: serverDisconnectedAt ?? Date.now(),
474‚Üí						serverName: serverName || null,
475‚Üí					});
476‚Üí				}
477‚Üí			}
478‚Üí			return;
479‚Üí		}
480‚Üí
481‚Üí		// Authenticated client ‚Äî forward data to server
482‚Üí		const tunnel = this.getTunnel();
483‚Üí		if (tunnel) {
484‚Üí			this.safeSend(tunnel, {
485‚Üí				type: "data",
486‚Üí				clientId,
487‚Üí				payload: JSON.stringify(json),
488‚Üí			});
489‚Üí		}
490‚Üí	}
491‚Üí
492‚Üí	// ---- Pairer Message Handling ----
493‚Üí
494‚Üí	private async handlePairerMessage(pairId: string, frame: PairerFrame): Promise<void> {
495‚Üí		const isPending = await this.ctx.storage.get<number>(`pending:pair:${pairId}`);
496‚Üí		if (isPending === undefined) return;
497‚Üí
498‚Üí		const tunnel = this.getTunnel();
499‚Üí		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
500‚Üí		if (tunnel && isRegistered) {
501‚Üí			this.safeSend(tunnel, {
502‚Üí				type: "pair_request",
503‚Üí				pairId,
504‚Üí				code: frame.code,
505‚Üí				deviceName: frame.deviceName,
506‚Üí			});
507‚Üí		} else {
508‚Üí			const pairerWs = this.findPairerWs(pairId);
509‚Üí			if (pairerWs) {
510‚Üí				this.safeSend(pairerWs, { type: "pair_failed", message: "Server is offline" });
511‚Üí				try {
512‚Üí					pairerWs.close(1000, "Server offline");
513‚Üí				} catch (err) {
514‚Üí					console.error("relay: failed to close pairer (server offline)", err);
515‚Üí				}
516‚Üí			}
517‚Üí			await this.ctx.storage.delete(`pending:pair:${pairId}`);
518‚Üí		}
519‚Üí	}
520‚Üí
521‚Üí	// ---- Client/Server Lifecycle ----
522‚Üí
523‚Üí	private async handleClientDisconnect(clientId: string): Promise<void> {
524‚Üí		await this.ctx.storage.delete(`pending:${clientId}`);
525‚Üí		await this.ctx.storage.delete(`auth_token:${clientId}`);
526‚Üí
527‚Üí		const tunnel = this.getTunnel();
528‚Üí		if (tunnel) {
529‚Üí			this.safeSend(tunnel, {
530‚Üí				type: "client_disconnected",
531‚Üí				clientId,
532‚Üí			});
533‚Üí		}
534‚Üí	}
535‚Üí
536‚Üí	private async handleServerDisconnect(): Promise<void> {
537‚Üí		// If another tunnel is already active (e.g. old tunnel's close callback firing
538‚Üí		// after handleTunnel replaced it), skip the disconnect flow.
539‚Üí		const tunnels = this.ctx.getWebSockets("tunnel");
540‚Üí		if (tunnels.length > 0) return;
541‚Üí
542‚Üí		const existing = await this.ctx.storage.get<number>("serverDisconnectedAt");
543‚Üí		if (existing !== undefined) return; // Already handling disconnect
544‚Üí
545‚Üí		await this.ctx.storage.put("tunnelRegistered", false);
546‚Üí		const disconnectedAt = Date.now();
547‚Üí		await this.ctx.storage.put("serverDisconnectedAt", disconnectedAt);
548‚Üí
549‚Üí		const serverName = await this.ctx.storage.get<string>("serverName");
550‚Üí		const clients = this.ctx.getWebSockets("client");
551‚Üí		for (const clientWs of clients) {
552‚Üí			this.safeSend(clientWs, {
553‚Üí				type: "server_reconnecting",
554‚Üí				serverDisconnectedAt: disconnectedAt,
555‚Üí				serverName: serverName || null,
556‚Üí			});
557‚Üí		}
558‚Üí
559‚Üí		await this.scheduleNextAlarm();
560‚Üí	}
561‚Üí
562‚Üí	// ---- Data Forwarding ----
563‚Üí
564‚Üí	private async forwardToClient(clientId: string, payload: string): Promise<void> {
565‚Üí		const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
566‚Üí		if (isPending !== undefined) {
567‚Üí			return;
568‚Üí		}
569‚Üí
570‚Üí		const ws = this.findClientWs(clientId);
571‚Üí		if (ws) {
572‚Üí			try {
573‚Üí				ws.send(payload);
574‚Üí			} catch (err) {
575‚Üí				console.error(`relay: failed to forward data to client ${clientId}`, err);
576‚Üí			}
577‚Üí		}
578‚Üí	}
579‚Üí
580‚Üí	// ---- Alarm Scheduling ----
581‚Üí
582‚Üí	private async scheduleNextAlarm(): Promise<void> {
583‚Üí		const now = Date.now();
584‚Üí		const candidates: number[] = [];
585‚Üí
586‚Üí		// Earliest pending auth deadline
587‚Üí		const pendingClients = await this.ctx.storage.list<number>({ prefix: "pending:" });
588‚Üí		for (const [, deadline] of pendingClients) {
589‚Üí			candidates.push(deadline);
590‚Üí		}
591‚Üí
592‚Üí		// Earliest pending pair deadline
593‚Üí		const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
594‚Üí		for (const [, deadline] of pendingPairs) {
595‚Üí			candidates.push(deadline);
596‚Üí		}
597‚Üí
598‚Üí		// Heartbeat interval (only if server is connected)
599‚Üí		const tunnels = this.ctx.getWebSockets("tunnel");
600‚Üí		if (tunnels.length > 0) {
601‚Üí			candidates.push(now + HEARTBEAT_INTERVAL_MS);
602‚Üí		}
603‚Üí
604‚Üí		if (candidates.length > 0) {
605‚Üí			const nextAlarm = Math.min(...candidates);
606‚Üí			// Ensure alarm is at least 100ms in the future
607‚Üí			await this.ctx.storage.setAlarm(Math.max(nextAlarm, now + 100));
608‚Üí		}
609‚Üí	}
610‚Üí
611‚Üí	// ---- Helpers ----
612‚Üí
613‚Üí	/** Get pending client auth entries, filtering out pair entries that share the prefix. */
614‚Üí	private async getPendingClients(): Promise<Map<string, number>> {
615‚Üí		const entries = await this.ctx.storage.list<number>({ prefix: "pending:" });
616‚Üí		const result = new Map<string, number>();
617‚Üí		for (const [key, deadline] of entries) {
618‚Üí			if (key.startsWith("pending:pair:")) continue;
619‚Üí			result.set(key.slice("pending:".length), deadline);
620‚Üí		}
621‚Üí		return result;
622‚Üí	}
623‚Üí
624‚Üí	private findClientWs(clientId: string): WebSocket | null {
625‚Üí		const allClients = this.ctx.getWebSockets("client");
626‚Üí		for (const ws of allClients) {
627‚Üí			const tags = this.ctx.getTags(ws);
628‚Üí			if (tags.includes(clientId)) return ws;
629‚Üí		}
630‚Üí		return null;
631‚Üí	}
632‚Üí
633‚Üí	private findPairerWs(pairId: string): WebSocket | null {
634‚Üí		const allPairers = this.ctx.getWebSockets("pairer");
635‚Üí		for (const ws of allPairers) {
636‚Üí			const tags = this.ctx.getTags(ws);
637‚Üí			if (tags.includes(pairId)) return ws;
638‚Üí		}
639‚Üí		return null;
640‚Üí	}
641‚Üí
642‚Üí	private getTunnel(): WebSocket | null {
643‚Üí		const tunnels = this.ctx.getWebSockets("tunnel");
644‚Üí		return tunnels[0] ?? null;
645‚Üí	}
646‚Üí
647‚Üí	private safeSend(ws: WebSocket, data: RelayFrame | RelayClientFrame | RelayPairerFrame): void {
648‚Üí		try {
649‚Üí			ws.send(JSON.stringify(data));
650‚Üí		} catch (err) {
651‚Üí			console.error("relay: safeSend failed", err);
652‚Üí		}
653‚Üí	}
654‚Üí}
