  1‚Üí// backend/src/services/relay.service.ts
  2‚Üí// Manages the outbound WebSocket tunnel to the cloud relay.
  3‚Üí// Creates virtual WsConnections in ws.service for relay-forwarded clients.
  4‚Üí// Registers the query-engine protocol handler for q:* frames.
  5‚Üí
  6‚Üíimport { execSync } from "child_process";
  7‚Üíimport { hostname, userInfo, platform } from "os";
  8‚Üíimport { WebSocket } from "ws";
  9‚Üíimport { match } from "ts-pattern";
 10‚Üíimport type { ServerFrame, RelayFrame } from "@shared/types/relay";
 11‚Üíimport { getSetting, saveSetting } from "./settings.service";
 12‚Üíimport {
 13‚Üí  getRelayCredentials,
 14‚Üí  generateRelayCredentials,
 15‚Üí  validateDeviceToken,
 16‚Üí  validatePairCode,
 17‚Üí  createDeviceToken,
 18‚Üí} from "./remote-auth.service";
 19‚Üíimport { DEFAULT_RELAY_URL } from "../lib/network";
 20‚Üíimport {
 21‚Üí  addConnection,
 22‚Üí  removeConnection,
 23‚Üí  getConnection,
 24‚Üí  setProtocolHandlers,
 25‚Üí  handleProtocolMessage,
 26‚Üí  type WsSendable,
 27‚Üí} from "./ws.service";
 28‚Üíimport { handleFrame as handleQueryFrame, removeSubs as removeQuerySubs } from "./query-engine";
 29‚Üí
 30‚Üí// ---- Tunnel State ----
 31‚Üí
 32‚Üílet tunnelWs: WebSocket | null = null;
 33‚Üílet relayUrl: string | null = null;
 34‚Üílet serverId: string | null = null;
 35‚Üílet relayToken: string | null = null;
 36‚Üílet reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 37‚Üílet reconnectAttempt = 0;
 38‚Üí
 39‚Üí// ---- Bidirectional Client Map ----
 40‚Üí// Maps relay clientId <-> ws.service connectionId. Both directions O(1).
 41‚Üí// The invariant: every key in clientToConn exists exactly once in connToClient.
 42‚Üí
 43‚Üíconst clientToConn = new Map<string, string>();
 44‚Üíconst connToClient = new Map<string, string>();
 45‚Üí
 46‚Üífunction linkClient(clientId: string, connectionId: string): void {
 47‚Üí  clientToConn.set(clientId, connectionId);
 48‚Üí  connToClient.set(connectionId, clientId);
 49‚Üí}
 50‚Üí
 51‚Üífunction unlinkClient(clientId: string): string | undefined {
 52‚Üí  const connectionId = clientToConn.get(clientId);
 53‚Üí  if (connectionId) connToClient.delete(connectionId);
 54‚Üí  clientToConn.delete(clientId);
 55‚Üí  return connectionId;
 56‚Üí}
 57‚Üí
 58‚Üífunction unlinkAll(): void {
 59‚Üí  clientToConn.clear();
 60‚Üí  connToClient.clear();
 61‚Üí}
 62‚Üí
 63‚Üíconst MAX_RECONNECT_DELAY = 30_000;
 64‚Üíconst BASE_RECONNECT_DELAY = 1_000;
 65‚Üí
 66‚Üí// ---- Server Name Detection ----
 67‚Üí
 68‚Üífunction getServerName(): string {
 69‚Üí  const custom = getSetting("server_name") as string | undefined;
 70‚Üí  if (custom) return custom;
 71‚Üí
 72‚Üí  if (platform() === "darwin") {
 73‚Üí    try {
 74‚Üí      const name = execSync("scutil --get ComputerName", {
 75‚Üí        encoding: "utf-8",
 76‚Üí        timeout: 2000,
 77‚Üí      }).trim();
 78‚Üí      if (name) return name;
 79‚Üí    } catch {
 80‚Üí      /* fall through */
 81‚Üí    }
 82‚Üí  }
 83‚Üí
 84‚Üí  const host = hostname().replace(/\.local$/, "");
 85‚Üí  if (host && host !== "localhost") return host;
 86‚Üí
 87‚Üí  try {
 88‚Üí    return `${userInfo().username}'s computer`;
 89‚Üí  } catch {
 90‚Üí    return "OpenDevs Server";
 91‚Üí  }
 92‚Üí}
 93‚Üí
 94‚Üí// ---- Protocol Handler ----
 95‚Üí// Registered once at module load. Routes q:* frames to the query engine.
 96‚Üí
 97‚ÜísetProtocolHandlers({
 98‚Üí  onQueryFrame: handleQueryFrame,
 99‚Üí});
100‚Üí
101‚Üí// ---- Public API ----
102‚Üí
103‚Üíexport function ensureRelayConnected(): void {
104‚Üí  let url = getSetting("relay_url") as string | null;
105‚Üí  if (!url) {
106‚Üí    url = DEFAULT_RELAY_URL;
107‚Üí    saveSetting("relay_url", url);
108‚Üí  }
109‚Üí  let creds = getRelayCredentials();
110‚Üí  if (!creds) {
111‚Üí    creds = generateRelayCredentials();
112‚Üí  }
113‚Üí  // Already connected or connecting with same credentials ‚Äî skip
114‚Üí  if (
115‚Üí    relayUrl === url &&
116‚Üí    serverId === creds.serverId &&
117‚Üí    relayToken === creds.relayToken &&
118‚Üí    tunnelWs &&
119‚Üí    (tunnelWs.readyState === WebSocket.OPEN || tunnelWs.readyState === WebSocket.CONNECTING)
120‚Üí  ) {
121‚Üí    return;
122‚Üí  }
123‚Üí
124‚Üí  connectToRelay(url, creds.serverId, creds.relayToken);
125‚Üí}
126‚Üí
127‚Üíexport function connectToRelay(url: string, id: string, token: string): void {
128‚Üí  relayUrl = url;
129‚Üí  serverId = id;
130‚Üí  relayToken = token;
131‚Üí  reconnectAttempt = 0;
132‚Üí  openTunnel();
133‚Üí}
134‚Üí
135‚Üíexport function disconnectFromRelay(): void {
136‚Üí  relayUrl = null;
137‚Üí  serverId = null;
138‚Üí  relayToken = null;
139‚Üí  if (reconnectTimer) {
140‚Üí    clearTimeout(reconnectTimer);
141‚Üí    reconnectTimer = null;
142‚Üí  }
143‚Üí  if (tunnelWs) {
144‚Üí    tunnelWs.close(1000, "Disconnecting");
145‚Üí    tunnelWs = null;
146‚Üí  }
147‚Üí  for (const [, connId] of clientToConn) {
148‚Üí    removeQuerySubs(connId);
149‚Üí    removeConnection(connId);
150‚Üí  }
151‚Üí  unlinkAll();
152‚Üí}
153‚Üí
154‚Üíexport function getRelayStatus(): {
155‚Üí  connected: boolean;
156‚Üí  clients: number;
157‚Üí  serverId: string | null;
158‚Üí  relayUrl: string | null;
159‚Üí} {
160‚Üí  const effectiveUrl = relayUrl ?? (getSetting("relay_url") as string | undefined) ?? null;
161‚Üí  const creds = serverId ? null : getRelayCredentials();
162‚Üí  const effectiveServerId = serverId ?? creds?.serverId ?? null;
163‚Üí
164‚Üí  return {
165‚Üí    connected: tunnelWs?.readyState === WebSocket.OPEN,
166‚Üí    clients: clientToConn.size,
167‚Üí    serverId: effectiveServerId,
168‚Üí    relayUrl: effectiveUrl,
169‚Üí  };
170‚Üí}
171‚Üí
172‚Üí// ---- Tunnel Lifecycle ----
173‚Üí
174‚Üífunction openTunnel(): void {
175‚Üí  if (!relayUrl || !serverId || !relayToken) return;
176‚Üí
177‚Üí  const wsUrl = `${relayUrl}/api/servers/${serverId}/tunnel?token=${encodeURIComponent(relayToken)}`;
178‚Üí  console.log(`[Relay] Connecting to ${relayUrl}/api/servers/${serverId}/tunnel...`);
179‚Üí
180‚Üí  try {
181‚Üí    tunnelWs = new WebSocket(wsUrl);
182‚Üí  } catch (err) {
183‚Üí    console.error("[Relay] Failed to create WebSocket:", err);
184‚Üí    scheduleReconnect();
185‚Üí    return;
186‚Üí  }
187‚Üí
188‚Üí  tunnelWs.on("open", () => {
189‚Üí    console.log("[Relay] Tunnel connected, registering...");
190‚Üí    reconnectAttempt = 0;
191‚Üí    sendToRelay({
192‚Üí      type: "register",
193‚Üí      serverId: serverId!,
194‚Üí      relayToken: relayToken!,
195‚Üí      serverName: getServerName(),
196‚Üí    });
197‚Üí  });
198‚Üí
199‚Üí  tunnelWs.on("message", (raw: Buffer | string) => {
200‚Üí    try {
201‚Üí      const frame = JSON.parse(typeof raw === "string" ? raw : raw.toString()) as RelayFrame;
202‚Üí      handleRelayFrame(frame);
203‚Üí    } catch {
204‚Üí      // Ignore malformed frames
205‚Üí    }
206‚Üí  });
207‚Üí
208‚Üí  tunnelWs.on("close", (code, reason) => {
209‚Üí    console.log(`[Relay] Tunnel closed: ${code} ${reason}`);
210‚Üí    tunnelWs = null;
211‚Üí    for (const [, connId] of clientToConn) {
212‚Üí      removeQuerySubs(connId);
213‚Üí      removeConnection(connId);
214‚Üí    }
215‚Üí    unlinkAll();
216‚Üí    if (relayUrl) scheduleReconnect();
217‚Üí  });
218‚Üí
219‚Üí  tunnelWs.on("error", (err) => {
220‚Üí    console.error("[Relay] Tunnel error:", err.message);
221‚Üí  });
222‚Üí}
223‚Üí
224‚Üífunction handleRelayFrame(frame: RelayFrame): void {
225‚Üí  match(frame)
226‚Üí    .with({ type: "registered" }, () => {
227‚Üí      console.log("[Relay] Registered with relay successfully");
228‚Üí    })
229‚Üí    .with({ type: "client_connected" }, (f) => {
230‚Üí      const device = validateDeviceToken(f.deviceToken);
231‚Üí      if (device) {
232‚Üí        // Clean up existing connection (idempotent on tunnel reconnect)
233‚Üí        const existingConnId = clientToConn.get(f.clientId);
234‚Üí        if (existingConnId) {
235‚Üí          removeQuerySubs(existingConnId);
236‚Üí          removeConnection(existingConnId);
237‚Üí        }
238‚Üí
239‚Üí        // Virtual WsSendable routes data back through the relay tunnel
240‚Üí        const virtualWs: WsSendable = {
241‚Üí          send(data: string | ArrayBuffer) {
242‚Üí            const payload =
243‚Üí              typeof data === "string" ? data : new TextDecoder().decode(data as ArrayBuffer);
244‚Üí            sendToRelay({ type: "data", clientId: f.clientId, payload });
245‚Üí          },
246‚Üí          close() {
247‚Üí            // No-op ‚Äî relay manages client disconnect
248‚Üí          },
249‚Üí        };
250‚Üí        const connId = addConnection(virtualWs, device.id, true);
251‚Üí        linkClient(f.clientId, connId);
252‚Üí        sendToRelay({ type: "auth_response", clientId: f.clientId, allowed: true });
253‚Üí        console.log(`[Relay] Client ${f.clientId} authenticated as device ${device.name}`);
254‚Üí      } else {
255‚Üí        sendToRelay({
256‚Üí          type: "auth_response",
257‚Üí          clientId: f.clientId,
258‚Üí          allowed: false,
259‚Üí          reason: "Invalid device token",
260‚Üí        });
261‚Üí        console.log(`[Relay] Client ${f.clientId} auth rejected`);
262‚Üí      }
263‚Üí    })
264‚Üí    .with({ type: "client_disconnected" }, (f) => {
265‚Üí      const connId = unlinkClient(f.clientId);
266‚Üí      if (connId) {
267‚Üí        removeQuerySubs(connId);
268‚Üí        removeConnection(connId);
269‚Üí        console.log(`[Relay] Client ${f.clientId} disconnected`);
270‚Üí      }
271‚Üí    })
272‚Üí    .with({ type: "data" }, (f) => {
273‚Üí      const connId = clientToConn.get(f.clientId);
274‚Üí      if (!connId) return;
275‚Üí      if (!getConnection(connId)) return;
276‚Üí
277‚Üí      try {
278‚Üí        const msg = JSON.parse(f.payload) as Record<string, unknown>;
279‚Üí        // Unified protocol handler ‚Äî same as local WS clients
280‚Üí        handleProtocolMessage(connId, msg);
281‚Üí      } catch {
282‚Üí        // Ignore malformed inner messages
283‚Üí      }
284‚Üí    })
285‚Üí    .with({ type: "pair_request" }, (f) => {
286‚Üí      handlePairRequest(f.pairId, f.code, f.deviceName);
287‚Üí    })
288‚Üí    .with({ type: "ping" }, () => {
289‚Üí      sendToRelay({ type: "pong" });
290‚Üí    })
291‚Üí    .with({ type: "error" }, (f) => {
292‚Üí      console.error(`[Relay] Error from relay: ${f.message}`);
293‚Üí    })
294‚Üí    .exhaustive();
295‚Üí}
296‚Üí
297‚Üí// ---- Pairing ----
298‚Üí
299‚Üífunction handlePairRequest(pairId: string, code: string, deviceName: string): void {
300‚Üí  if (!validatePairCode(code)) {
301‚Üí    sendToRelay({
302‚Üí      type: "pair_response",
303‚Üí      pairId,
304‚Üí      success: false,
305‚Üí      reason: "Invalid or expired pairing code",
306‚Üí    });
307‚Üí    console.log(`[Relay] Pair request ${pairId} rejected: invalid code`);
308‚Üí    return;
309‚Üí  }
310‚Üí
311‚Üí  const { token } = createDeviceToken(deviceName || "Web Portal", null, "relay-paired");
312‚Üí  sendToRelay({ type: "pair_response", pairId, success: true, deviceToken: token });
313‚Üí  console.log(`[Relay] Pair request ${pairId} succeeded, device "${deviceName}" paired`);
314‚Üí}
315‚Üí
316‚Üí// ---- Helpers ----
317‚Üí
318‚Üífunction sendToRelay(frame: ServerFrame): void {
319‚Üí  if (tunnelWs?.readyState === WebSocket.OPEN) {
320‚Üí    try {
321‚Üí      tunnelWs.send(JSON.stringify(frame));
322‚Üí    } catch {
323‚Üí      // Will be handled by close/error handlers
324‚Üí    }
325‚Üí  }
326‚Üí}
327‚Üí
328‚Üífunction scheduleReconnect(): void {
329‚Üí  if (reconnectTimer) return;
330‚Üí  const delay = Math.min(BASE_RECONNECT_DELAY * 2 ** reconnectAttempt, MAX_RECONNECT_DELAY);
331‚Üí  reconnectAttempt++;
332‚Üí  console.log(`[Relay] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})...`);
333‚Üí  reconnectTimer = setTimeout(() => {
334‚Üí    reconnectTimer = null;
335‚Üí    openTunnel();
336‚Üí  }, delay);
337‚Üí}
