  1‚Üí// backend/src/services/agent/tool-relay.ts
  2‚Üí// Manages pending tool requests being relayed from the agent-server to the frontend.
  3‚Üí//
  4‚Üí// Flow:
  5‚Üí//   Agent emits tool.request event
  6‚Üí//   ‚Üí handleAgentEvent calls toolRelay.relay()
  7‚Üí//   ‚Üí Backend pushes q:event { event: "tool:request", data: {...} } to all frontend WS clients
  8‚Üí//   ‚Üí Frontend handles the request (browser automation, diff, terminal, plan, question)
  9‚Üí//   ‚Üí Frontend sends q:tool_response { requestId, result/error } back via WS
 10‚Üí//   ‚Üí Backend calls toolRelay.resolve/reject
 11‚Üí//   ‚Üí relay() promise resolves ‚Üí agent-event-handler sends result back to agent-server
 12‚Üí//
 13‚Üí// Timeout handling: each tool request has a timeout (set by the agent-server).
 14‚Üí// If the frontend doesn't respond within the timeout, the pending promise is rejected.
 15‚Üí
 16‚Üíimport type { ToolRequestEvent } from "@shared/agent-events";
 17‚Üíimport type { ToolRequestEventData, QServerFrame } from "@shared/types/query-protocol";
 18‚Üíimport { broadcast } from "../ws.service";
 19‚Üí
 20‚Üí// ---- Types ----
 21‚Üí
 22‚Üíinterface PendingRelay {
 23‚Üí  resolve: (result: unknown) => void;
 24‚Üí  reject: (error: Error) => void;
 25‚Üí  timer: ReturnType<typeof setTimeout>;
 26‚Üí  sessionId: string;
 27‚Üí  method: string;
 28‚Üí}
 29‚Üí
 30‚Üí// ---- Singleton State ----
 31‚Üí
 32‚Üíconst pending = new Map<string, PendingRelay>();
 33‚Üí
 34‚Üí// ---- Public API ----
 35‚Üí
 36‚Üí/**
 37‚Üí * Relay a tool request from the agent to the frontend via WebSocket.
 38‚Üí *
 39‚Üí * Returns a promise that resolves when the frontend sends back q:tool_response,
 40‚Üí * or rejects if the timeout expires.
 41‚Üí *
 42‚Üí * The caller (agent-event-handler) uses the resolved value to send the result
 43‚Üí * back to the agent-server via agentClient.sendTurnRespond().
 44‚Üí */
 45‚Üíexport function relay(event: ToolRequestEvent): Promise<unknown> {
 46‚Üí  const { requestId, sessionId, method, params, timeoutMs } = event;
 47‚Üí
 48‚Üí  // If there's already a pending request with this ID, reject the old one
 49‚Üí  // (shouldn't happen in practice, but prevents leaked promises)
 50‚Üí  const existing = pending.get(requestId);
 51‚Üí  if (existing) {
 52‚Üí    clearTimeout(existing.timer);
 53‚Üí    existing.reject(new Error(`Superseded by new relay for requestId=${requestId}`));
 54‚Üí    pending.delete(requestId);
 55‚Üí  }
 56‚Üí
 57‚Üí  return new Promise<unknown>((resolve, reject) => {
 58‚Üí    // Set timeout ‚Äî reject if frontend doesn't respond in time
 59‚Üí    const timer = setTimeout(() => {
 60‚Üí      pending.delete(requestId);
 61‚Üí      reject(
 62‚Üí        new Error(
 63‚Üí          `Tool relay timed out after ${timeoutMs}ms (requestId=${requestId}, method=${method})`
 64‚Üí        )
 65‚Üí      );
 66‚Üí    }, timeoutMs);
 67‚Üí
 68‚Üí    // Store the pending relay
 69‚Üí    pending.set(requestId, { resolve, reject, timer, sessionId, method });
 70‚Üí
 71‚Üí    // Push q:event to all connected frontend clients
 72‚Üí    const eventData: ToolRequestEventData = {
 73‚Üí      requestId,
 74‚Üí      sessionId,
 75‚Üí      method,
 76‚Üí      params,
 77‚Üí      timeoutMs,
 78‚Üí    };
 79‚Üí
 80‚Üí    const frame: QServerFrame = {
 81‚Üí      type: "q:event",
 82‚Üí      event: "tool:request",
 83‚Üí      data: eventData,
 84‚Üí    };
 85‚Üí
 86‚Üí    broadcast(JSON.stringify(frame));
 87‚Üí  });
 88‚Üí}
 89‚Üí
 90‚Üí/**
 91‚Üí * Resolve a pending tool relay with the frontend's response.
 92‚Üí * Called when the query engine receives a q:tool_response frame with a result.
 93‚Üí */
 94‚Üíexport function resolve(requestId: string, result: unknown): boolean {
 95‚Üí  const entry = pending.get(requestId);
 96‚Üí  if (!entry) return false;
 97‚Üí
 98‚Üí  clearTimeout(entry.timer);
 99‚Üí  pending.delete(requestId);
100‚Üí  entry.resolve(result);
101‚Üí  return true;
102‚Üí}
103‚Üí
104‚Üí/**
105‚Üí * Reject a pending tool relay with an error from the frontend.
106‚Üí * Called when the query engine receives a q:tool_response frame with an error.
107‚Üí */
108‚Üíexport function reject(requestId: string, error: string): boolean {
109‚Üí  const entry = pending.get(requestId);
110‚Üí  if (!entry) return false;
111‚Üí
112‚Üí  clearTimeout(entry.timer);
113‚Üí  pending.delete(requestId);
114‚Üí  entry.reject(new Error(error));
115‚Üí  return true;
116‚Üí}
117‚Üí
118‚Üí/**
119‚Üí * Get the number of pending relays (for diagnostics / tests).
120‚Üí */
121‚Üíexport function getPendingCount(): number {
122‚Üí  return pending.size;
123‚Üí}
124‚Üí
125‚Üí/**
126‚Üí * Clear all pending relays (for shutdown / tests).
127‚Üí * Rejects all pending promises with a shutdown error.
128‚Üí */
129‚Üíexport function clearAll(): void {
130‚Üí  for (const [requestId, entry] of pending) {
131‚Üí    clearTimeout(entry.timer);
132‚Üí    entry.reject(new Error(`Tool relay cleared (requestId=${requestId})`));
133‚Üí  }
134‚Üí  pending.clear();
135‚Üí}
136‚Üí

