  1‚Üí// backend/src/services/ws.service.ts
  2‚Üí// WebSocket connection manager for remote access.
  3‚Üí// Manages connected clients, heartbeat pings, message routing, and protocol dispatch.
  4‚Üí
  5‚Üíimport { match } from "ts-pattern";
  6‚Üíimport type { WSContext } from "hono/ws";
  7‚Üí
  8‚Üí/** Minimal interface for sending/closing WebSocket-like connections.
  9‚Üí *  WSContext already satisfies this ‚Äî used to also accept virtual relay connections. */
 10‚Üíexport interface WsSendable {
 11‚Üí  send(data: string | ArrayBuffer): void;
 12‚Üí  close(code?: number, reason?: string): void;
 13‚Üí}
 14‚Üí
 15‚Üíexport interface WsConnection {
 16‚Üí  id: string;
 17‚Üí  ws: WsSendable;
 18‚Üí  deviceId: string | null;
 19‚Üí  lastPong: number;
 20‚Üí  /** True for relay-tunneled connections (skip direct heartbeat pings) */
 21‚Üí  isVirtual?: boolean;
 22‚Üí}
 23‚Üí
 24‚Üí// ---- State ----
 25‚Üí
 26‚Üíconst connections = new Map<string, WsConnection>();
 27‚Üílet heartbeatInterval: ReturnType<typeof setInterval> | null = null;
 28‚Üí
 29‚Üíconst HEARTBEAT_INTERVAL_MS = 30_000;
 30‚Üíconst HEARTBEAT_TIMEOUT_MS = 10_000;
 31‚Üí
 32‚Üí// ---- Public API ----
 33‚Üí
 34‚Üí/** Register a new WebSocket connection. Returns the connection ID. */
 35‚Üíexport function addConnection(ws: WsSendable, deviceId: string | null, isVirtual = false): string {
 36‚Üí  const id = crypto.randomUUID();
 37‚Üí  connections.set(id, {
 38‚Üí    id,
 39‚Üí    ws,
 40‚Üí    deviceId,
 41‚Üí    lastPong: Date.now(),
 42‚Üí    isVirtual,
 43‚Üí  });
 44‚Üí
 45‚Üí  startHeartbeat();
 46‚Üí  return id;
 47‚Üí}
 48‚Üí
 49‚Üí/** Remove a connection by ID. */
 50‚Üíexport function removeConnection(id: string): void {
 51‚Üí  connections.delete(id);
 52‚Üí  if (connections.size === 0) stopHeartbeat();
 53‚Üí}
 54‚Üí
 55‚Üí/** Get a connection by ID. */
 56‚Üíexport function getConnection(id: string): WsConnection | undefined {
 57‚Üí  return connections.get(id);
 58‚Üí}
 59‚Üí
 60‚Üí/** Record a pong from a client. */
 61‚Üíexport function recordPong(id: string): void {
 62‚Üí  const conn = connections.get(id);
 63‚Üí  if (conn) conn.lastPong = Date.now();
 64‚Üí}
 65‚Üí
 66‚Üí/** Broadcast a message to all connected clients. */
 67‚Üíexport function broadcast(message: string): void {
 68‚Üí  for (const conn of connections.values()) {
 69‚Üí    try {
 70‚Üí      conn.ws.send(message);
 71‚Üí    } catch {
 72‚Üí      // Connection may have closed ‚Äî will be cleaned up on next heartbeat
 73‚Üí    }
 74‚Üí  }
 75‚Üí}
 76‚Üí
 77‚Üí/** Get number of active connections. */
 78‚Üíexport function getConnectionCount(): number {
 79‚Üí  return connections.size;
 80‚Üí}
 81‚Üí
 82‚Üí/** Close all connections and stop heartbeat (for shutdown). */
 83‚Üíexport function closeAll(): void {
 84‚Üí  stopHeartbeat();
 85‚Üí  for (const conn of connections.values()) {
 86‚Üí    try {
 87‚Üí      conn.ws.close(1001, "Server shutting down");
 88‚Üí    } catch {
 89‚Üí      // Best-effort
 90‚Üí    }
 91‚Üí  }
 92‚Üí  connections.clear();
 93‚Üí}
 94‚Üí
 95‚Üí// ---- Heartbeat ----
 96‚Üí
 97‚Üífunction startHeartbeat(): void {
 98‚Üí  if (heartbeatInterval) return;
 99‚Üí  heartbeatInterval = setInterval(checkHeartbeats, HEARTBEAT_INTERVAL_MS);
100‚Üí}
101‚Üí
102‚Üífunction stopHeartbeat(): void {
103‚Üí  if (heartbeatInterval) {
104‚Üí    clearInterval(heartbeatInterval);
105‚Üí    heartbeatInterval = null;
106‚Üí  }
107‚Üí}
108‚Üí
109‚Üífunction checkHeartbeats(): void {
110‚Üí  const now = Date.now();
111‚Üí  for (const [id, conn] of connections) {
112‚Üí    // Virtual connections are managed by the relay tunnel ‚Äî skip direct heartbeat
113‚Üí    if (conn.isVirtual) continue;
114‚Üí
115‚Üí    if (now - conn.lastPong > HEARTBEAT_INTERVAL_MS + HEARTBEAT_TIMEOUT_MS) {
116‚Üí      // Client hasn't responded to pings ‚Äî close
117‚Üí      console.log(`[WS] Closing stale connection: ${id}`);
118‚Üí      try {
119‚Üí        conn.ws.close(1001, "Heartbeat timeout");
120‚Üí      } catch {
121‚Üí        // Already closed
122‚Üí      }
123‚Üí      connections.delete(id);
124‚Üí      continue;
125‚Üí    }
126‚Üí
127‚Üí    // Send ping
128‚Üí    try {
129‚Üí      conn.ws.send(JSON.stringify({ type: "ping" }));
130‚Üí    } catch {
131‚Üí      connections.delete(id);
132‚Üí    }
133‚Üí  }
134‚Üí
135‚Üí  if (connections.size === 0) stopHeartbeat();
136‚Üí}
137‚Üí
138‚Üí// ---- Protocol Dispatch ----
139‚Üí
140‚Üí/** Handler for q:* query protocol frames. */
141‚Üíexport interface WsProtocolHandlers {
142‚Üí  onQueryFrame?: (connectionId: string, msg: Record<string, unknown>) => void;
143‚Üí}
144‚Üí
145‚Üílet extendedHandlers: WsProtocolHandlers = {};
146‚Üí
147‚Üí/** Register handlers for extended protocol messages. Called once at startup. */
148‚Üíexport function setProtocolHandlers(handlers: WsProtocolHandlers): void {
149‚Üí  extendedHandlers = handlers;
150‚Üí}
151‚Üí
152‚Üí/**
153‚Üí * Handle an incoming WS protocol message for an authenticated connection.
154‚Üí * Shared by local WS (app.ts) and virtual relay connections (relay.service.ts).
155‚Üí *
156‚Üí * Core: pong
157‚Üí * Query protocol: q:* frames routed to query engine
158‚Üí */
159‚Üíexport function handleProtocolMessage(connectionId: string, msg: Record<string, unknown>): void {
160‚Üí  match(msg.type as string)
161‚Üí    .with("pong", () => {
162‚Üí      recordPong(connectionId);
163‚Üí    })
164‚Üí    .otherwise(() => {
165‚Üí      // Route q:* frames to query engine handler
166‚Üí      if (typeof msg.type === "string" && msg.type.startsWith("q:")) {
167‚Üí        extendedHandlers.onQueryFrame?.(connectionId, msg);
168‚Üí      }
169‚Üí    });
170‚Üí}
171‚Üí

 1‚Üíexport const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";
