 3‚Üíexport function isLocalhost(ip: string | undefined): boolean {
 4‚Üí  if (!ip) return false;
 5‚Üí  return ip === "127.0.0.1" || ip === "::1" || ip === "::ffff:127.0.0.1" || ip === "localhost";
 6‚Üí}
