10‚Üí    (c.env as any)?.incoming?.socket?.remoteAddress ||
11‚Üí    c.req.header("x-forwarded-for")?.split(",")[0]?.trim() ||
12‚Üí    c.req.header("x-real-ip")
13‚Üí  );
14‚Üí}
