  1‚Üíimport { Hono } from "hono";
  2‚Üíimport { cors } from "hono/cors";
  3‚Üíimport { createNodeWebSocket } from "@hono/node-ws";
  4‚Üíimport { errorHandler } from "./middleware/error-handler";
  5‚Üíimport { remoteGateMiddleware } from "./middleware/remote-gate";
  6‚Üíimport { authMiddleware } from "./middleware/remote-auth";
  7‚Üíimport { validateDeviceToken } from "./services/remote-auth.service";
  8‚Üíimport { addConnection, removeConnection, handleProtocolMessage } from "./services/ws.service";
  9‚Üíimport { removeSubs as removeQuerySubs } from "./services/query-engine";
 10‚Üíimport { getRelayStatus } from "./services/relay.service";
 11‚Üíimport { isLocalhost, getClientIp } from "./lib/network";
 12‚Üíimport healthRoutes from "./routes/health";
 13‚Üíimport workspaceRoutes from "./routes/workspaces";
 14‚Üíimport workspaceDiffRoutes from "./routes/workspaces.diff";
 15‚Üíimport workspacePrRoutes from "./routes/workspaces.pr";
 16‚Üíimport workspaceDesignRoutes from "./routes/workspaces.design";
 17‚Üíimport sessionRoutes from "./routes/sessions";
 18‚Üíimport repoRoutes from "./routes/repos";
 19‚Üíimport agentConfigRoutes from "./routes/agent-config";
 20‚Üíimport settingsRoutes from "./routes/settings";
 21‚Üíimport statsRoutes from "./routes/stats";
 22‚Üíimport onboardingRoutes from "./routes/onboarding";
 23‚Üíimport authRoutes from "./routes/remote-auth";
 24‚Üíimport filesRoutes from "./routes/files";
 25‚Üí// Legacy sidecar HTTP relay routes removed ‚Äî all agent communication
 26‚Üí// now goes through WebSocket AgentClient (services/agent/client.ts)
 27‚Üí
 28‚Üíexport function createApp() {
 29‚Üí  const app = new Hono();
 30‚Üí  const { upgradeWebSocket, injectWebSocket } = createNodeWebSocket({ app });
 31‚Üí
 32‚Üí  // Middleware ‚Äî order matters:
 33‚Üí  // 1. Remote gate rejects non-localhost when remote access is disabled
 34‚Üí  // 2. CORS headers for browser requests
 35‚Üí  // 3. Auth validates Bearer tokens for remote clients (localhost exempt)
 36‚Üí  app.use("*", remoteGateMiddleware);
 37‚Üí  app.use("*", cors());
 38‚Üí  app.use("/api/*", authMiddleware);
 39‚Üí
 40‚Üí  // Mount route groups
 41‚Üí  app.route("/api", healthRoutes);
 42‚Üí  app.route("/api", authRoutes);
 43‚Üí  app.route("/api", workspaceRoutes);
 44‚Üí  app.route("/api", workspaceDiffRoutes);
 45‚Üí  app.route("/api", workspacePrRoutes);
 46‚Üí  app.route("/api", workspaceDesignRoutes);
 47‚Üí  app.route("/api", sessionRoutes);
 48‚Üí  app.route("/api", repoRoutes);
 49‚Üí  app.route("/api", agentConfigRoutes);
 50‚Üí  app.route("/api", settingsRoutes);
 51‚Üí  app.route("/api", statsRoutes);
 52‚Üí  app.route("/api", filesRoutes);
 53‚Üí  // Legacy sidecar HTTP routes removed (replaced by WS AgentClient)
 54‚Üí  app.route("/api", onboardingRoutes);
 55‚Üí
 56‚Üí  // Relay status endpoint
 57‚Üí  app.get("/api/relay/status", (c) => {
 58‚Üí    return c.json(getRelayStatus());
 59‚Üí  });
 60‚Üí
 61‚Üí  // WebSocket route for remote access.
 62‚Üí  // Localhost connections are auto-authenticated. Remote clients must send
 63‚Üí  // { type: "initialize", token: "..." } as their first message.
 64‚Üí  app.get(
 65‚Üí    "/ws",
 66‚Üí    upgradeWebSocket((c) => {
 67‚Üí      const ip = getClientIp(c);
 68‚Üí      const isLocal = isLocalhost(ip);
 69‚Üí      let connectionId: string | null = null;
 70‚Üí
 71‚Üí      return {
 72‚Üí        onOpen(_evt, ws) {
 73‚Üí          if (isLocal) {
 74‚Üí            // Desktop/localhost connections skip token auth
 75‚Üí            connectionId = addConnection(ws, null);
 76‚Üí            ws.send(JSON.stringify({ type: "connected", connectionId }));
 77‚Üí          }
 78‚Üí          // Remote clients stay unauthenticated until initialize message
 79‚Üí        },
 80‚Üí
 81‚Üí        onMessage(evt, ws) {
 82‚Üí          let msg: Record<string, unknown>;
 83‚Üí          try {
 84‚Üí            const raw = typeof evt.data === "string" ? evt.data : String(evt.data);
 85‚Üí            msg = JSON.parse(raw);
 86‚Üí          } catch {
 87‚Üí            return; // Ignore malformed messages
 88‚Üí          }
 89‚Üí
 90‚Üí          // Unauthenticated remote client ‚Äî must initialize first
 91‚Üí          if (!connectionId) {
 92‚Üí            if (msg.type === "initialize" && typeof msg.token === "string") {
 93‚Üí              const device = validateDeviceToken(msg.token);
 94‚Üí              if (device) {
 95‚Üí                connectionId = addConnection(ws, device.id);
 96‚Üí                ws.send(JSON.stringify({ type: "connected", connectionId }));
 97‚Üí              } else {
 98‚Üí                ws.send(JSON.stringify({ type: "error", message: "Invalid token" }));
 99‚Üí                ws.close(4001, "Invalid token");
100‚Üí              }
101‚Üí            } else {
102‚Üí              ws.send(
103‚Üí                JSON.stringify({ type: "error", message: "Must send initialize with token" })
104‚Üí              );
105‚Üí              ws.close(4001, "Not authenticated");
106‚Üí            }
107‚Üí            return;
108‚Üí          }
109‚Üí
110‚Üí          // Authenticated ‚Äî handle protocol messages (shared with relay virtual connections)
111‚Üí          handleProtocolMessage(connectionId, msg);
112‚Üí        },
113‚Üí
114‚Üí        onClose() {
115‚Üí          if (connectionId) {
116‚Üí            removeQuerySubs(connectionId);
117‚Üí            removeConnection(connectionId);
118‚Üí            connectionId = null;
119‚Üí          }
120‚Üí        },
121‚Üí      };
122‚Üí    })
123‚Üí  );
124‚Üí
125‚Üí  // Centralized error handling
126‚Üí  app.onError(errorHandler);
127‚Üí
128‚Üí  return { app, injectWebSocket };
129‚Üí}
