127‚Üí	send(data: unknown): void {
128‚Üí		if (this.ws?.readyState === WebSocket.OPEN) {
129‚Üí			this.ws.send(JSON.stringify(data));
130‚Üí		}
131‚Üí	}
132‚Üí
133‚Üí	/** One-shot pairing exchange: opens /pair WS, sends code, returns device token. */
134‚Üí	static pair(
135‚Üí		relayUrl: string,
136‚Üí		serverId: string,
137‚Üí		code: string,
138‚Üí		deviceName: string,
139‚Üí	): Promise<string> {
140‚Üí		return new Promise((resolve, reject) => {
141‚Üí			const url = `${relayUrl}/api/servers/${serverId}/pair`;
142‚Üí			let ws: WebSocket;
143‚Üí			try {
144‚Üí				ws = new WebSocket(url);
145‚Üí			} catch {
146‚Üí				return reject(new Error("Failed to open pairing connection"));
147‚Üí			}
148‚Üí
149‚Üí			const timeout = setTimeout(() => {
150‚Üí				ws.close();
151‚Üí				reject(new Error("Pairing timed out"));
152‚Üí			}, 30_000);
153‚Üí
154‚Üí			const cleanup = () => clearTimeout(timeout);
155‚Üí			let settled = false;
156‚Üí			const finish = (fn: () => void) => {
157‚Üí				if (settled) return;
158‚Üí				settled = true;
159‚Üí				cleanup();
160‚Üí				fn();
161‚Üí			};
162‚Üí
163‚Üí			ws.onopen = () => {
164‚Üí				ws.send(JSON.stringify({ type: "pair_request", code, deviceName }));
165‚Üí			};
166‚Üí
167‚Üí			ws.onmessage = (event) => {
168‚Üí				try {
169‚Üí					const data = JSON.parse(event.data) as RelayPairerFrame;
170‚Üí					if (data.type === "pair_success") {
171‚Üí						finish(() => {
172‚Üí							ws.close(1000);
173‚Üí							resolve(data.token);
174‚Üí						});
175‚Üí					} else if (data.type === "pair_failed") {
176‚Üí						finish(() => {
177‚Üí							ws.close(1000);
178‚Üí							reject(new Error(data.message || "Pairing failed"));
179‚Üí						});
180‚Üí					}
181‚Üí					// Ignore unrelated messages ‚Äî keep timeout running
182‚Üí				} catch {
183‚Üí					finish(() => {
184‚Üí						ws.close();
185‚Üí						reject(new Error("Invalid response from relay"));
186‚Üí					});
187‚Üí				}
188‚Üí			};
189‚Üí
190‚Üí			ws.onerror = () => {
191‚Üí				finish(() => reject(new Error("Connection to relay failed")));
192‚Üí			};
193‚Üí
194‚Üí			ws.onclose = (ev) => {
195‚Üí				if (ev.code !== 1000) {
196‚Üí					finish(() => reject(new Error("Connection closed unexpectedly")));
197‚Üí				}
198‚Üí			};
199‚Üí		});
200‚Üí	}
201‚Üí
202‚Üí	disconnect(): void {
203‚Üí		this.disposed = true;
204‚Üí		if (this.reconnectTimer) {
205‚Üí			clearTimeout(this.reconnectTimer);
206‚Üí			this.reconnectTimer = null;
207‚Üí		}
208‚Üí		if (this.ws) {
209‚Üí			this.ws.close(1000, "Client disconnecting");
210‚Üí			this.ws = null;
211‚Üí		}
212‚Üí	}
213‚Üí
214‚Üí	private scheduleReconnect(): void {
215‚Üí		if (this.disposed || this.reconnectTimer) return;
216‚Üí		const delay = Math.min(1000 * 2 ** this.reconnectAttempt, 30_000);
217‚Üí		this.reconnectAttempt++;
218‚Üí		this.reconnectTimer = setTimeout(() => {
219‚Üí			this.reconnectTimer = null;
220‚Üí			this.connect();
221‚Üí		}, delay);
222‚Üí	}
223‚Üí}
224‚Üí

  1‚Üí// ServerConnectionProvider ‚Äî React context that owns RelayClient + QueryTransport.
  2‚Üí// Routes incoming q:* frames to QueryTransport. Components access connection via useServerConnection().
  3‚Üí
  4‚Üíimport type { QueryClientFrame, QueryInvalidate, QueryServerFrame } from "@cancun/types";
  5‚Üíimport { useQueryClient } from "@tanstack/react-query";
  6‚Üíimport {
  7‚Üí	type ReactNode,
  8‚Üí	createContext,
  9‚Üí	useCallback,
 10‚Üí	useContext,
 11‚Üí	useEffect,
 12‚Üí	useRef,
 13‚Üí	useState,
 14‚Üí} from "react";
 15‚Üíimport { RELAY_HTTP_URL, RELAY_WS_URL } from "./env";
 16‚Üíimport { QueryTransport } from "./query-transport";
 17‚Üíimport { RelayClient, type RelayStatus, type ServerOfflineInfo } from "./relay-client";
 18‚Üíimport { addSavedServer, getSavedServers } from "./storage";
 19‚Üí
 20‚Üí// ‚îÄ‚îÄ Types ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 21‚Üí
 22‚Üíexport interface ServerConnectionValue {
 23‚Üí	connStatus: RelayStatus;
 24‚Üí	error: string | null;
 25‚Üí	serverName: string | null;
 26‚Üí	offlineInfo: ServerOfflineInfo | null;
 27‚Üí	transport: QueryTransport | null;
 28‚Üí	serverId: string;
 29‚Üí	reconnect: () => void;
 30‚Üí}
 31‚Üí
 32‚Üíconst ServerConnectionContext = createContext<ServerConnectionValue | null>(null);
 33‚Üí
 34‚Üí// ‚îÄ‚îÄ Provider ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 35‚Üí
 36‚Üíexport function ServerConnectionProvider({
 37‚Üí	serverId,
 38‚Üí	token,
 39‚Üí	children,
 40‚Üí}: {
 41‚Üí	serverId: string;
 42‚Üí	token: string;
 43‚Üí	children: ReactNode;
 44‚Üí}) {
 45‚Üí	const queryClient = useQueryClient();
 46‚Üí
 47‚Üí	const [connStatus, setConnStatus] = useState<RelayStatus>("disconnected");
 48‚Üí	const [error, setError] = useState<string | null>(null);
 49‚Üí	const [serverName, setServerName] = useState<string | null>(() => {
 50‚Üí		const saved = getSavedServers().find((s) => s.id === serverId);
 51‚Üí		return saved?.name || null;
 52‚Üí	});
 53‚Üí	const [offlineInfo, setOfflineInfo] = useState<ServerOfflineInfo | null>(null);
 54‚Üí
 55‚Üí	const transportRef = useRef<QueryTransport | null>(null);
 56‚Üí	const clientRef = useRef<RelayClient | null>(null);
 57‚Üí	const connStatusRef = useRef<RelayStatus>(connStatus);
 58‚Üí
 59‚Üí	// ‚îÄ‚îÄ Route incoming messages ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 60‚Üí
 61‚Üí	const handleMessage = useCallback(
 62‚Üí		(data: unknown) => {
 63‚Üí			const msg = data as Record<string, unknown>;
 64‚Üí			const type = msg.type as string;
 65‚Üí
 66‚Üí			// q:* frames ‚Üí QueryTransport
 67‚Üí			if (type?.startsWith("q:")) {
 68‚Üí				if (type === "q:invalidate") {
 69‚Üí					const frame = msg as QueryInvalidate;
 70‚Üí					for (const resource of frame.resources) {
 71‚Üí						queryClient.invalidateQueries({ queryKey: ["server", serverId, resource] });
 72‚Üí					}
 73‚Üí					return;
 74‚Üí				}
 75‚Üí				transportRef.current?.handleServerFrame(msg as QueryServerFrame);
 76‚Üí				return;
 77‚Üí			}
 78‚Üí
 79‚Üí			// Server name from initial_state (still useful for display)
 80‚Üí			if (type === "initial_state") {
 81‚Üí				const state = msg as { serverName?: string };
 82‚Üí				if (state.serverName) {
 83‚Üí					setServerName(state.serverName);
 84‚Üí					addSavedServer(serverId, state.serverName);
 85‚Üí				}
 86‚Üí				return;
 87‚Üí			}
 88‚Üí		},
 89‚Üí		[serverId, queryClient],
 90‚Üí	);
 91‚Üí
 92‚Üí	// ‚îÄ‚îÄ Initialize RelayClient + QueryTransport ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 93‚Üí
 94‚Üí	useEffect(() => {
 95‚Üí		const sendFn: (frame: QueryClientFrame) => void = (frame) => clientRef.current?.send(frame);
 96‚Üí
 97‚Üí		const transport = new QueryTransport(sendFn);
 98‚Üí		transportRef.current = transport;
 99‚Üí
100‚Üí		const client = new RelayClient({
101‚Üí			relayUrl: RELAY_WS_URL,
102‚Üí			serverId,
103‚Üí			token,
104‚Üí			onStatusChange: (status) => {
105‚Üí				connStatusRef.current = status;
106‚Üí				setConnStatus(status);
107‚Üí				if (status === "connected") {
108‚Üí					setOfflineInfo(null);
109‚Üí					setError(null);
110‚Üí					transport.resubscribeAll(sendFn);
111‚Üí				}
112‚Üí				if (status === "disconnected" || status === "error") {
113‚Üí					transport.rejectAll("Disconnected");
114‚Üí				}
115‚Üí			},
116‚Üí			onMessage: handleMessage,
117‚Üí			onError: (err) => setError(err),
118‚Üí			onServerOffline: (info) => {
119‚Üí				setOfflineInfo(info);
120‚Üí				if (info?.serverName) setServerName(info.serverName);
121‚Üí			},
122‚Üí		});
123‚Üí
124‚Üí		clientRef.current = client;
125‚Üí		client.connect();
126‚Üí
127‚Üí		return () => {
128‚Üí			transport.destroy();
129‚Üí			client.disconnect();
130‚Üí			clientRef.current = null;
131‚Üí			transportRef.current = null;
132‚Üí		};
133‚Üí	}, [serverId, token, handleMessage]);
134‚Üí
135‚Üí	// ‚îÄ‚îÄ Prefetch server status via HTTP ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
136‚Üí
137‚Üí	useEffect(() => {
138‚Üí		let cancelled = false;
139‚Üí		fetch(`${RELAY_HTTP_URL}/api/servers/${serverId}/status`)
140‚Üí			.then((r) => (r.ok ? r.json() : null))
141‚Üí			.then((data) => {
142‚Üí				if (cancelled || !data || connStatusRef.current === "connected") return;
143‚Üí				if (data.serverName) setServerName((prev) => prev ?? data.serverName);
144‚Üí				if (!data.online && data.serverDisconnectedAt) {
145‚Üí					setOfflineInfo({
146‚Üí						serverName: data.serverName || null,
147‚Üí						disconnectedAt: data.serverDisconnectedAt,
148‚Üí					});
149‚Üí				}
150‚Üí			})
151‚Üí			.catch((err) => console.warn("[prefetch] Server status check failed:", err.message));
152‚Üí		return () => {
153‚Üí			cancelled = true;
154‚Üí		};
155‚Üí	}, [serverId]);
156‚Üí
157‚Üí	// ‚îÄ‚îÄ Context value ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
158‚Üí
159‚Üí	const value: ServerConnectionValue = {
160‚Üí		connStatus,
161‚Üí		error,
162‚Üí		serverName,
163‚Üí		offlineInfo,
164‚Üí		transport: transportRef.current,
165‚Üí		serverId,
166‚Üí		reconnect: () => clientRef.current?.connect(),
167‚Üí	};
168‚Üí
169‚Üí	return (
170‚Üí		<ServerConnectionContext.Provider value={value}>{children}</ServerConnectionContext.Provider>
171‚Üí	);
172‚Üí}
173‚Üí
174‚Üí// ‚îÄ‚îÄ Hook ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
175‚Üí
176‚Üíexport function useServerConnection() {
177‚Üí	const ctx = useContext(ServerConnectionContext);
178‚Üí	if (!ctx) throw new Error("useServerConnection must be within ServerConnectionProvider");
179‚Üí	return ctx;
180‚Üí}
181‚Üí

  1‚Üí// QueryTransport ‚Äî request correlation, subscriptions, and mutation handling.
  2‚Üí// Plain TypeScript class with no React dependency. Unit-testable with mock send functions.
  3‚Üí//
  4‚Üí// Phase 1: Created but not yet the primary data path (legacy bridge handles it).
  5‚Üí// Phase 2+: Becomes the primary transport when server supports q:* frames.
  6‚Üí
  7‚Üíimport type {
  8‚Üí	MutationName,
  9‚Üí	MutationParams,
 10‚Üí	MutationResult,
 11‚Üí	QueryClientFrame,
 12‚Üí	QueryServerFrame,
 13‚Üí	ResourceName,
 14‚Üí} from "@cancun/types";
 15‚Üí
 16‚Üítype SendFn = (frame: QueryClientFrame) => void;
 17‚Üí
 18‚Üítype PendingRequest = {
 19‚Üí	resolve: (data: unknown) => void;
 20‚Üí	reject: (error: Error) => void;
 21‚Üí	timer: ReturnType<typeof setTimeout>;
 22‚Üí};
 23‚Üí
 24‚Üítype ActiveSubscription = {
 25‚Üí	resource: ResourceName;
 26‚Üí	params: Record<string, unknown>;
 27‚Üí	onSnapshot: (data: unknown) => void;
 28‚Üí	onDelta: (upserted?: unknown[], removed?: string[]) => void;
 29‚Üí};
 30‚Üí
 31‚Üíexport class QueryTransport {
 32‚Üí	private send: SendFn;
 33‚Üí	private pending = new Map<string, PendingRequest>();
 34‚Üí	private subscriptions = new Map<string, ActiveSubscription>();
 35‚Üí	private counter = 0;
 36‚Üí	private timeoutMs = 10_000;
 37‚Üí
 38‚Üí	constructor(send: SendFn) {
 39‚Üí		this.send = send;
 40‚Üí	}
 41‚Üí
 42‚Üí	// ‚îÄ‚îÄ One-shot query ‚Üí Promise ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 43‚Üí
 44‚Üí	fetch(resource: ResourceName, params?: Record<string, unknown>): Promise<unknown> {
 45‚Üí		const id = `rq_${++this.counter}`;
 46‚Üí		return new Promise((resolve, reject) => {
 47‚Üí			const timer = setTimeout(() => {
 48‚Üí				this.pending.delete(id);
 49‚Üí				reject(new Error(`Query timeout: ${resource}`));
 50‚Üí			}, this.timeoutMs);
 51‚Üí
 52‚Üí			this.pending.set(id, { resolve, reject, timer });
 53‚Üí			this.send({ type: "q:request", id, resource, params });
 54‚Üí		});
 55‚Üí	}
 56‚Üí
 57‚Üí	// ‚îÄ‚îÄ Subscribe ‚Üí snapshot + deltas ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 58‚Üí
 59‚Üí	subscribe(
 60‚Üí		resource: ResourceName,
 61‚Üí		params: Record<string, unknown>,
 62‚Üí		onSnapshot: (data: unknown) => void,
 63‚Üí		onDelta: (upserted?: unknown[], removed?: string[]) => void,
 64‚Üí	): () => void {
 65‚Üí		const id = `sub_${++this.counter}`;
 66‚Üí
 67‚Üí		this.subscriptions.set(id, { resource, params, onSnapshot, onDelta });
 68‚Üí		this.send({ type: "q:subscribe", id, resource, params });
 69‚Üí
 70‚Üí		return () => {
 71‚Üí			this.subscriptions.delete(id);
 72‚Üí			this.send({ type: "q:unsubscribe", id });
 73‚Üí		};
 74‚Üí	}
 75‚Üí
 76‚Üí	// ‚îÄ‚îÄ Mutation ‚Üí Promise (typed) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
 77‚Üí
 78‚Üí	mutate<M extends MutationName>(
 79‚Üí		action: M,
 80‚Üí		params: MutationParams<M>,
 81‚Üí	): Promise<{ success: boolean; data?: MutationResult<M>; error?: string }> {
 82‚Üí		const id = `mut_${++this.counter}`;
 83‚Üí		return new Promise((resolve, reject) => {
 84‚Üí			const timer = setTimeout(() => {
 85‚Üí				this.pending.delete(id);
 86‚Üí				reject(new Error(`Mutation timeout: ${action}`));
 87‚Üí			}, this.timeoutMs);
 88‚Üí
 89‚Üí			this.pending.set(id, {
 90‚Üí				resolve: (data) =>
 91‚Üí					resolve(data as { success: boolean; data?: MutationResult<M>; error?: string }),
 92‚Üí				reject,
 93‚Üí				timer,
 94‚Üí			});
 95‚Üí			this.send({ type: "q:mutate", id, action, params: params as Record<string, unknown> });
 96‚Üí		});
 97‚Üí	}
 98‚Üí
 99‚Üí	// ‚îÄ‚îÄ Route incoming server frames ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
100‚Üí
101‚Üí	handleServerFrame(frame: QueryServerFrame): void {
102‚Üí		switch (frame.type) {
103‚Üí			case "q:response":
104‚Üí			case "q:mutate_result": {
105‚Üí				const pending = this.pending.get(frame.id);
106‚Üí				if (!pending) return;
107‚Üí				clearTimeout(pending.timer);
108‚Üí				this.pending.delete(frame.id);
109‚Üí				if (frame.type === "q:response") {
110‚Üí					pending.resolve(frame.data);
111‚Üí				} else {
112‚Üí					pending.resolve(frame);
113‚Üí				}
114‚Üí				break;
115‚Üí			}
116‚Üí
117‚Üí			case "q:error": {
118‚Üí				const pending = this.pending.get(frame.id);
119‚Üí				if (!pending) return;
120‚Üí				clearTimeout(pending.timer);
121‚Üí				this.pending.delete(frame.id);
122‚Üí				pending.reject(new Error(`${frame.code}: ${frame.message}`));
123‚Üí				break;
124‚Üí			}
125‚Üí
126‚Üí			case "q:snapshot": {
127‚Üí				const sub = this.subscriptions.get(frame.id);
128‚Üí				if (sub) sub.onSnapshot(frame.data);
129‚Üí				break;
130‚Üí			}
131‚Üí
132‚Üí			case "q:delta": {
133‚Üí				const sub = this.subscriptions.get(frame.id);
134‚Üí				if (sub) sub.onDelta(frame.upserted, frame.removed);
135‚Üí				break;
136‚Üí			}
137‚Üí
138‚Üí			// q:invalidate is handled by ServerConnectionProvider
139‚Üí		}
140‚Üí	}
141‚Üí
142‚Üí	// ‚îÄ‚îÄ Reconnection: replay all subscriptions ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
143‚Üí
144‚Üí	resubscribeAll(newSend: SendFn): void {
145‚Üí		this.send = newSend;
