// Relay envelope protocol types.
// Defines the framing between Deus server ‚Üî CF Durable Object relay ‚Üî web clients.

import { z } from "zod";

// ---- Server ‚Üî Relay (tunnel) ----

/** Frames sent from Deus server to relay via tunnel WebSocket */
export type ServerFrame =
	| { type: "register"; serverId: string; relayToken: string; serverName?: string }
	| { type: "data"; clientId: string; payload: string }
	| { type: "auth_response"; clientId: string; allowed: boolean; reason?: string }
	| {
			type: "pair_response";
			pairId: string;
			success: boolean;
			deviceToken?: string;
			reason?: string;
	  }
	| { type: "pong" };

/** Frames sent from relay to Deus server via tunnel WebSocket */
export type RelayFrame =
	| { type: "registered" }
	| { type: "client_connected"; clientId: string; deviceToken: string }
	| { type: "client_disconnected"; clientId: string }
	| { type: "data"; clientId: string; payload: string }
	| { type: "pair_request"; pairId: string; code: string; deviceName: string }
	| { type: "ping" }
	| { type: "error"; message: string };

// ---- Client ‚Üî Relay ----

/** First message a client sends after WebSocket connect */
export type ClientAuthFrame = { type: "authenticate"; token: string };

/** Control frames sent from relay to client (auth + lifecycle) */
export type RelayClientFrame =
	| { type: "authenticated" }
	| { type: "auth_failed"; message: string }
	| { type: "server_offline"; serverName: string | null; serverDisconnectedAt: number }
	| { type: "server_reconnecting"; serverName: string | null; serverDisconnectedAt: number }
	| { type: "server_connected" }
	| { type: "error"; message: string };

// ---- Pairer ‚Üî Relay ----

/** Frame sent from pairer (web browser) to relay */
export type PairerFrame = { type: "pair_request"; code: string; deviceName: string };

/** Frames sent from relay to pairer */
export type RelayPairerFrame =
	| { type: "pair_success"; token: string }
	| { type: "pair_failed"; message: string };

// ---- Zod Schemas (inbound validation) ----

export const serverFrameSchema = z.discriminatedUnion("type", [
	z.object({
		type: z.literal("register"),
		serverId: z.string(),
		relayToken: z.string(),
		serverName: z.string().optional(),
	}),
	z.object({
		type: z.literal("data"),
		clientId: z.string(),
		payload: z.string(),
	}),
	z.object({
		type: z.literal("auth_response"),
		clientId: z.string(),
		allowed: z.boolean(),
		reason: z.string().optional(),
	}),
	z.object({
		type: z.literal("pair_response"),
		pairId: z.string(),
		success: z.boolean(),
		deviceToken: z.string().optional(),
		reason: z.string().optional(),
	}),
	z.object({ type: z.literal("pong") }),
]);

export const clientAuthFrameSchema = z.object({
	type: z.literal("authenticate"),
	token: z.string(),
});

export const pairerFrameSchema = z.object({
	type: z.literal("pair_request"),
	code: z.string(),
	deviceName: z.string().default("Web Browser"),
});
