export type ResourceName = keyof typeof resources;
export type ResourceParams<R extends ResourceName> = z.infer<(typeof resources)[R]["params"]>;
export type ResourceRow<R extends ResourceName> = z.infer<(typeof resources)[R]["row"]>;

// ‚îÄ‚îÄ Mutation Registry ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

export const mutations = {
	sendMessage: {
		params: z.object({ sessionId: z.string(), content: z.string() }),
		result: z.object({ messageId: z.string(), seq: z.number() }),
	},
	archiveWorkspace: {
