app.get("/api/servers/:serverId/status", withRelay, async (c) => {
	const stub = c.get("stub");
	return stub.fetch(new Request(new URL("/status", c.req.url)));
});

// Root
app.get("/", (c) =>
	c.json({
		name: "rundeus-relay",
		version: "0.1.0",
		docs: "https://app.rundeus.com",
