// ‚îÄ‚îÄ Frame Types (Client ‚Üí Server) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

export type QueryRequest = {
	type: "q:request";
	id: string;
	resource: ResourceName;
	params?: Record<string, unknown>;
};

export type QuerySubscribe = {
	type: "q:subscribe";
	id: string;
	resource: ResourceName;
	params?: Record<string, unknown>;
};

export type QueryUnsubscribe = {
	type: "q:unsubscribe";
	id: string;
};

export type QueryMutate = {
	type: "q:mutate";
	id: string;
	action: MutationName;
	params: Record<string, unknown>;
};

export type QueryClientFrame = QueryRequest | QuerySubscribe | QueryUnsubscribe | QueryMutate;

// ‚îÄ‚îÄ Frame Types (Server ‚Üí Client) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

export type QueryResponse = {
	type: "q:response";
	id: string;
	data: unknown;
};

export type QuerySnapshot = {
	type: "q:snapshot";
	id: string;
	data: unknown;
	cursor?: number;
};

export type QueryDelta = {
	type: "q:delta";
	id: string;
