234‚Üí        if (existingConnId) {
235‚Üí          removeQuerySubs(existingConnId);
236‚Üí          removeConnection(existingConnId);
237‚Üí        }
238‚Üí
239‚Üí        // Virtual WsSendable routes data back through the relay tunnel
240‚Üí        const virtualWs: WsSendable = {
241‚Üí          send(data: string | ArrayBuffer) {
