243‚Üí              typeof data === "string" ? data : new TextDecoder().decode(data as ArrayBuffer);
244‚Üí            sendToRelay({ type: "data", clientId: f.clientId, payload });
245‚Üí          },
246‚Üí          close() {
247‚Üí            // No-op ‚Äî relay manages client disconnect
248‚Üí          },
249‚Üí        };
250‚Üí        const connId = addConnection(virtualWs, device.id, true);
251‚Üí        linkClient(f.clientId, connId);
252‚Üí        sendToRelay({ type: "auth_response", clientId: f.clientId, allowed: true });
253‚Üí        console.log(`[Relay] Client ${f.clientId} authenticated as device ${device.name}`);
254‚Üí      } else {
255‚Üí        sendToRelay({
256‚Üí          type: "auth_response",
257‚Üí          clientId: f.clientId,
258‚Üí          allowed: false,
259‚Üí          reason: "Invalid device token",
260‚Üí        });
261‚Üí        console.log(`[Relay] Client ${f.clientId} auth rejected`);
262‚Üí      }
263‚Üí    })
264‚Üí    .with({ type: "client_disconnected" }, (f) => {
265‚Üí      const connId = unlinkClient(f.clientId);
266‚Üí      if (connId) {
267‚Üí        removeQuerySubs(connId);
268‚Üí        removeConnection(connId);
269‚Üí        console.log(`[Relay] Client ${f.clientId} disconnected`);
270‚Üí      }
271‚Üí    })
272‚Üí    .with({ type: "data" }, (f) => {
273‚Üí      const connId = clientToConn.get(f.clientId);
274‚Üí      if (!connId) return;
275‚Üí      if (!getConnection(connId)) return;
276‚Üí
277‚Üí      try {
278‚Üí        const msg = JSON.parse(f.payload) as Record<string, unknown>;
279‚Üí        // Unified protocol handler ‚Äî same as local WS clients
280‚Üí        handleProtocolMessage(connId, msg);
281‚Üí      } catch {
282‚Üí        // Ignore malformed inner messages
283‚Üí      }
284‚Üí    })
285‚Üí    .with({ type: "pair_request" }, (f) => {
286‚Üí      handlePairRequest(f.pairId, f.code, f.deviceName);
287‚Üí    })
288‚Üí    .with({ type: "ping" }, () => {
289‚Üí      sendToRelay({ type: "pong" });
290‚Üí    })
291‚Üí    .with({ type: "error" }, (f) => {
292‚Üí      console.error(`[Relay] Error from relay: ${f.message}`);
293‚Üí    })
294‚Üí    .exhaustive();
295‚Üí}
296‚Üí
297‚Üí// ---- Pairing ----
298‚Üí
299‚Üífunction handlePairRequest(pairId: string, code: string, deviceName: string): void {
300‚Üí  if (!validatePairCode(code)) {
301‚Üí    sendToRelay({
302‚Üí      type: "pair_response",
303‚Üí      pairId,
304‚Üí      success: false,
305‚Üí      reason: "Invalid or expired pairing code",
306‚Üí    });
307‚Üí    console.log(`[Relay] Pair request ${pairId} rejected: invalid code`);
308‚Üí    return;
309‚Üí  }
310‚Üí
311‚Üí  const { token } = createDeviceToken(deviceName || "Web Portal", null, "relay-paired");
312‚Üí  sendToRelay({ type: "pair_response", pairId, success: true, deviceToken: token });
313‚Üí  console.log(`[Relay] Pair request ${pairId} succeeded, device "${deviceName}" paired`);
314‚Üí}
315‚Üí
316‚Üí// ---- Helpers ----
317‚Üí
318‚Üífunction sendToRelay(frame: ServerFrame): void {
319‚Üí  if (tunnelWs?.readyState === WebSocket.OPEN) {
320‚Üí    try {
321‚Üí      tunnelWs.send(JSON.stringify(frame));
322‚Üí    } catch {
323‚Üí      // Will be handled by close/error handlers
324‚Üí    }
325‚Üí  }
326‚Üí}
327‚Üí
328‚Üífunction scheduleReconnect(): void {
329‚Üí  if (reconnectTimer) return;
330‚Üí  const delay = Math.min(BASE_RECONNECT_DELAY * 2 ** reconnectAttempt, MAX_RECONNECT_DELAY);
331‚Üí  reconnectAttempt++;
332‚Üí  console.log(`[Relay] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})...`);
333‚Üí  reconnectTimer = setTimeout(() => {
334‚Üí    reconnectTimer = null;
335‚Üí    openTunnel();
336‚Üí  }, delay);
337‚Üí}
