56‚Üí// ---- Zod Schemas (inbound validation) ----
57‚Üí
58‚Üíexport const serverFrameSchema = z.discriminatedUnion("type", [
59‚Üí	z.object({
60‚Üí		type: z.literal("register"),
61‚Üí		serverId: z.string(),
