  1‚Üí/**
  2‚Üí * Auto-Updater
  3‚Üí *
  4‚Üí * Uses electron-updater to check for updates on GitHub Releases.
  5‚Üí * Sends update state to the renderer via webContents.send so the
  6‚Üí * frontend can show update toasts.
  7‚Üí */
  8‚Üí
  9‚Üíimport { type BrowserWindow, ipcMain } from "electron";
 10‚Üíimport { autoUpdater, type UpdateInfo, type ProgressInfo } from "electron-updater";
 11‚Üí
 12‚Üíexport type UpdateState =
 13‚Üí  | { status: "idle" }
 14‚Üí  | { status: "checking" }
 15‚Üí  | { status: "available"; info: UpdateInfo }
 16‚Üí  | { status: "not-available" }
 17‚Üí  | { status: "downloading"; progress: ProgressInfo }
 18‚Üí  | { status: "downloaded"; info: UpdateInfo }
 19‚Üí  | { status: "error"; error: string };
 20‚Üí
 21‚Üílet currentState: UpdateState = { status: "idle" };
 22‚Üí
 23‚Üífunction sendState(win: BrowserWindow, state: UpdateState): void {
 24‚Üí  currentState = state;
 25‚Üí  if (win.isDestroyed() || win.webContents.isDestroyed()) return;
 26‚Üí  win.webContents.send("update:state", state);
 27‚Üí}
 28‚Üí
 29‚Üíexport function setupAutoUpdater(mainWindow: BrowserWindow): void {
 30‚Üí  autoUpdater.autoDownload = false;
 31‚Üí  autoUpdater.autoInstallOnAppQuit = true;
 32‚Üí
 33‚Üí  autoUpdater.on("checking-for-update", () => {
 34‚Üí    sendState(mainWindow, { status: "checking" });
 35‚Üí  });
 36‚Üí
 37‚Üí  autoUpdater.on("update-available", (info) => {
 38‚Üí    sendState(mainWindow, { status: "available", info });
 39‚Üí  });
 40‚Üí
 41‚Üí  autoUpdater.on("update-not-available", () => {
 42‚Üí    sendState(mainWindow, { status: "not-available" });
 43‚Üí  });
 44‚Üí
 45‚Üí  autoUpdater.on("download-progress", (progress) => {
 46‚Üí    sendState(mainWindow, { status: "downloading", progress });
 47‚Üí  });
 48‚Üí
 49‚Üí  autoUpdater.on("update-downloaded", (info) => {
 50‚Üí    sendState(mainWindow, { status: "downloaded", info });
 51‚Üí  });
 52‚Üí
 53‚Üí  autoUpdater.on("error", (err) => {
 54‚Üí    sendState(mainWindow, { status: "error", error: err.message });
 55‚Üí  });
 56‚Üí
 57‚Üí  // IPC handlers for renderer to control updates
 58‚Üí
 59‚Üí  ipcMain.handle("update:check", async () => {
 60‚Üí    try {
 61‚Üí      const result = await autoUpdater.checkForUpdates();
 62‚Üí      return result ? { updateInfo: result.updateInfo } : null;
 63‚Üí    } catch (err) {
 64‚Üí      console.error("[auto-updater] Check failed:", err);
 65‚Üí      return null;
 66‚Üí    }
 67‚Üí  });
 68‚Üí
 69‚Üí  ipcMain.handle("update:download", async () => {
 70‚Üí    try {
 71‚Üí      await autoUpdater.downloadUpdate();
 72‚Üí    } catch (err) {
 73‚Üí      console.error("[auto-updater] Download failed:", err);
 74‚Üí    }
 75‚Üí  });
 76‚Üí
 77‚Üí  ipcMain.handle("update:install", () => {
 78‚Üí    autoUpdater.quitAndInstall(false, true);
 79‚Üí  });
 80‚Üí
 81‚Üí  ipcMain.handle("update:getState", () => {
 82‚Üí    return currentState;
 83‚Üí  });
 84‚Üí
 85‚Üí  // Initial check after 15s delay (called from main/index.ts)
 86‚Üí  autoUpdater.checkForUpdates().catch((err) => {
 87‚Üí    console.error("[auto-updater] Initial check failed:", err);
 88‚Üí  });
 89‚Üí
 90‚Üí  // Periodic check every 4 hours
 91‚Üí  setInterval(
 92‚Üí    () => {
 93‚Üí      autoUpdater.checkForUpdates().catch((err) => {
 94‚Üí        console.error("[auto-updater] Periodic check failed:", err);
 95‚Üí      });
 96‚Üí    },
 97‚Üí    4 * 60 * 60 * 1000
 98‚Üí  );
 99‚Üí}
