53‚Üí
54‚Üí// Client connect ‚Äî remote web/mobile clients connect here
55‚Üíapp.get("/api/servers/:serverId/connect", withRelay, async (c) => {
56‚Üí	const stub = c.get("stub");
57‚Üí	const connectUrl = new URL(c.req.url);
58‚Üí	connectUrl.pathname = "/connect";
59‚Üí	return stub.fetch(new Request(connectUrl, c.req.raw));
60‚Üí});
61‚Üí
62‚Üí// Pairing exchange ‚Äî web portal exchanges a code for a device token
63‚Üíapp.get("/api/servers/:serverId/pair", withRelay, async (c) => {
64‚Üí	const stub = c.get("stub");
65‚Üí	const pairUrl = new URL(c.req.url);
66‚Üí	pairUrl.pathname = "/pair";
67‚Üí	return stub.fetch(new Request(pairUrl, c.req.raw));
68‚Üí});
69‚Üí
70‚Üí// Server status ‚Äî check if a server is online
71‚Üíapp.get("/api/servers/:serverId/status", withRelay, async (c) => {
72‚Üí	const stub = c.get("stub");
73‚Üí	return stub.fetch(new Request(new URL("/status", c.req.url)));
74‚Üí});
75‚Üí
76‚Üí// Root
77‚Üíapp.get("/", (c) =>
78‚Üí	c.json({
